B.uT=s([B.a0A,B.YA,B.a44,B.a4j,B.a_n,B.a_W,B.a29,B.a0X,B.a1I,B.a_w,B.a0D],t.zg)
B.aB4=new A.CR(B.cb,"\uc5d0\ub374\uc5d0 \uc624\uc2e0 \uac83\uc744 \ud658\uc601\ud574\uc694","\ud558\ub098\ub2d8\uacfc \ud568\uaed8\ud558\ub294 \ub9e4\uc77c\uc758 \uc5ec\uc815,\n\uc5d0\ub374\uc5d0\uc11c \uc2dc\uc791\ud558\uc138\uc694.")
B.aB5=new A.CR(B.fy,"\ub9e4\uc77c 5\ubd84, \ub9d0\uc500\uacfc \ud568\uaed8","\uc9e7\uc9c0\ub9cc \uae4a\uc740 \ubb35\uc0c1\uc73c\ub85c\n\ud558\ub8e8\ub97c \uc758\ubbf8 \uc788\uac8c \uc2dc\uc791\ud558\uc138\uc694.")
B.aB3=new A.CR(B.hS,"\ub098\ub9cc\uc758 \uc5d0\ub374\uc744 \uac00\uafd4\ubcf4\uc138\uc694","\ub9d0\uc500\uc744 \ubb35\uc0c1\ud560\uc218\ub85d\n\ub2f9\uc2e0\uc758 \uc815\uc6d0\uc774 \uc544\ub984\ub2f5\uac8c \uc790\ub77c\ub098\uc694.")
B.a_i=s([B.aB4,B.aB5,B.aB3],A.aw("G<CR>"))
B.WU=new A.b5("matthew-lesson-1","path-matthew","\uc608\uc218\ub2d8\uc740 \ub204\uad6c\uc2e0\uac00","\ub9c8\ud0dc\ubcf5\uc74c 1\uc7a5","\ub9c8\ud0dc\ubcf5\uc74c 1\uc7a5 1\uc808\ubd80\ud130 17\uc808\uc740 \uc608\uc218\ub2d8\uc758 \uacc4\ubcf4\ub97c \ud1b5\ud574 \uc774\ubd84\uc774 \ub204\uad6c\uc2e0\uc9c0\ub97c \ubcf4\uc5ec\uc8fc\ub294 \ubd80\ubd84\uc774\uc5d0\uc694. \ucc98\uc74c \uc77d\uc73c\uba74 \uc774\ub984\ub9cc \uacc4\uc18d \ub098\uc640\uc11c \uc870\uae08 \uc9c0\ub8e8\ud558\uac8c \ub290\uaef4\uc9c8 \uc218 \uc788\uc9c0\ub9cc, \uc0ac\uc2e4 \uc544\uc8fc \uc911\uc694\ud55c \uc758\ubbf8\uac00 \ub2f4\uaca8 \uc788\uc5b4\uc694. \ub9c8\ud0dc\ub294 \uc608\uc218\ub2d8\uc744 \u201c\uc544\ube0c\ub77c\ud568\uacfc \ub2e4\uc717\uc758 \uc790\uc190\u201d\uc774\ub77c\uace0 \uc18c\uac1c\ud558\uba74\uc11c, \uc774\ubd84\uc774 \ud558\ub098\ub2d8\uc774 \uc624\ub798\uc804\ubd80\ud130 \uc57d\uc18d\ud558\uc2e0 \uba54\uc2dc\uc544\ub77c\ub294 \uac83\uc744 \uac15\uc870\ud574\uc694. \uc544\ube0c\ub77c\ud568\uc740 \ud558\ub098\ub2d8\uc774 \ubcf5\uc744 \uc57d\uc18d\ud558\uc2e0 \uc0ac\ub78c\uc774\uace0, \ub2e4\uc717\uc740 \uc601\uc6d0\ud55c \uc655\uc5d0 \ub300\ud55c \uc57d\uc18d\uc744 \ubc1b\uc740 \uc0ac\ub78c\uc774\uc5d0\uc694. \uadf8\ub798\uc11c \uc608\uc218\ub2d8\uc740 \uadf8 \uc57d\uc18d\uc774 \uc2e4\uc81c\ub85c \uc774\ub8e8\uc5b4\uc9c4 \ubd84\uc774\ub77c\ub294 \uac83\uc744 \ubcf4\uc5ec\uc8fc\ub294 \uac70\uc608\uc694. \uacc4\ubcf4\uc5d0 \ub098\uc624\ub294 \ub9ce\uc740 \uc774\ub984\ub4e4\uc740 \ud558\ub098\ub2d8\uc774 \uc624\ub79c \uc2dc","\ub098\ub294 \ud558\ub098\ub2d8\uc758 \u201c\uc2dc\uac04\ud45c\u201d\ub97c \uc2e0\ub8b0\ud558\uace0 \uc788\ub098\uc694?")
B.WM=new A.b5("matthew-lesson-2","path-matthew","\uc608\uc218\ub2d8\uc758 \ud0c4\uc0dd","\ub9c8\ud0dc\ubcf5\uc74c 1\uc7a5","\ub9c8\ub9ac\uc544\ub294 \uc694\uc149\uacfc \uc815\ud63c\ud55c \uc0c1\ud0dc\uc600\uc9c0\ub9cc, \ud568\uaed8 \uc0b4\uae30 \uc804\uc5d0 \uc131\ub839\uc73c\ub85c \uc789\ud0dc\ub41c \uc0ac\uc2e4\uc774 \ub4dc\ub7ec\ub098\uc694.\n\uc774 \uc0c1\ud669\uc740 \ub2f9\uc2dc \uae30\uc900\uc73c\ub85c \ubcf4\uba74 \ub9e4\uc6b0 \ud070 \uc624\ud574\ub97c \uc0b4 \uc218 \uc788\ub294 \uc77c\uc774\uc5c8\uc5b4\uc694.\n\uc694\uc149\uc740 \uc758\ub85c\uc6b4 \uc0ac\ub78c\uc774\uc5b4\uc11c \ub9c8\ub9ac\uc544\ub97c \uacf5\uac1c\uc801\uc73c\ub85c \ub4dc\ub7ec\ub0b4\uc9c0 \uc54a\uace0 \uc870\uc6a9\ud788 \uad00\uacc4\ub97c \uc815\ub9ac\ud558\ub824\uace0 \ud588\uc5b4\uc694.\n\uadf8\ub54c \ud558\ub098\ub2d8\uc740 \ucc9c\uc0ac\ub97c \ud1b5\ud574 \uc694\uc149\uc5d0\uac8c \uc774 \uc77c\uc774 \uc131\ub839\uc73c\ub85c \ub41c \uac83\uc784\uc744 \uc54c\ub824\uc8fc\uc138\uc694.\n\uadf8\ub9ac\uace0 \ub9c8\ub9ac\uc544\ub97c \ub450\ub824\uc6cc\ud558\uc9c0 \ub9d0\uace0 \uc544\ub0b4\ub85c \ub9de\uc774\ud558\ub77c\uace0 \ub9d0\uc500\ud558\uc138\uc694.\n\ub610 \ud0dc\uc5b4\ub0a0 \uc544\uae30\uc758 \uc774\ub984\uc744 \u201c\uc608\uc218\u201d\ub77c\uace0 \ud558\ub77c\uace0 \ud558\uc2dc\ub294\ub370, \uc774\ub294 \uadf8\ubd84\uc774 \uc790\uae30 \ubc31\uc131\uc744 \uc8c4\uc5d0\uc11c \uad6c\uc6d0\ud558\uc2e4 \ubd84\uc774\ub77c\ub294 \ub73b\uc774\uc5d0\uc694.\n\uc774 \ubaa8\ub4e0 \uc77c\uc740 \ud558\ub098\ub2d8","\ub098\ub294 \uc774\ud574\ub418\uc9c0 \uc54a\ub294 \uc0c1\ud669\uc5d0\uc11c\ub3c4 \ud558\ub098\ub2d8\uc758 \ub73b\uc744 \uc2e0\ub8b0\ud560 \uc218 \uc788\ub098\uc694?")
B.WO=new A.b5("matthew-lesson-3","path-matthew","\ud558\ub098\ub2d8\uc758 \uc778\ub3c4\ud558\uc2ec\uc5d0 \uc21c\uc885\ud558\ub294 \uc0b6","\ub9c8\ud0dc\ubcf5\uc74c 2\uc7a5","\ub3d9\ubc29\uc5d0\uc11c \uc628 \ubc15\uc0ac\ub4e4\uc740 \ubcc4\uc744 \ubcf4\uace0 \uc720\ub300\uc778\uc758 \uc655\uc774 \ub098\uc168\ub2e4\ub294 \uc0ac\uc2e4\uc744 \uc54c\uace0 \uc608\uc218\ub2d8\uaed8 \uacbd\ubc30\ud558\ub7ec \uc654\uc5b4\uc694.\n\ud558\uc9c0\ub9cc \ud5e4\ub86f \uc655\uc740 \uc774 \uc18c\uc2dd\uc744 \ub4e3\uace0 \uc790\uc2e0\uc758 \uc655\uad8c\uc774 \uc704\ud611\ubc1b\ub294\ub2e4\uace0 \uc0dd\uac01\ud574 \ub450\ub824\uc6cc\ud588\uc5b4\uc694.\n\uadf8\ub798\uc11c \uac89\uc73c\ub85c\ub294 \uacbd\ubc30\ud558\uaca0\ub2e4\uace0 \ub9d0\ud558\uc9c0\ub9cc, \uc2e4\uc81c\ub85c\ub294 \uc608\uc218\ub2d8\uc744 \uc8fd\uc774\ub824\ub294 \uacc4\ud68d\uc744 \uc138\uc6cc\uc694.\n\ubc15\uc0ac\ub4e4\uc740 \ubcc4\uc758 \uc778\ub3c4\ub97c \ubc1b\uc544 \uc544\uae30 \uc608\uc218\ub2d8\uaed8 \ub098\uc544\uac00\uace0 \uae30\uc068\uc73c\ub85c \uacbd\ubc30\ud558\uba70 \uc608\ubb3c\uc744 \ub4dc\ub824\uc694.\n\ud558\ub098\ub2d8\uc740 \ubc15\uc0ac\ub4e4\uc5d0\uac8c \uafc8\uc73c\ub85c \uc9c0\uc2dc\ud558\uc154\uc11c \ud5e4\ub86f\uc5d0\uac8c \ub3cc\uc544\uac00\uc9c0 \uc54a\uac8c \ud558\uc2dc\uace0 \ub2e4\ub978 \uae38\ub85c \ub3cc\uc544\uac00\uac8c \ud558\uc138\uc694.\n\uc774\ud6c4 \ud558\ub098\ub2d8\uc740 \uc694\uc149\uc5d0\uac8c \ub098\ud0c0\ub098 \uc544\uae30 \uc608\uc218\ub97c \ubcf4\ud638\ud558\uae30 \uc704\ud574 \uc560\uad7d\uc73c\ub85c \ud53c\ud558\ub77c\uace0 \ub9d0\uc500\ud558\uc138\uc694.","\ub098\ub294 \uc608\uc218\ub2d8\uaed8 \ub098\uc544\uac00\ub294 \uc0ac\ub78c\uc778\uac00\uc694, \ud53c\ud558\ub294 \uc0ac\ub78c\uc778\uac00\uc694?")
B.Xc=new A.b5("matthew-lesson-4","path-matthew","\ud68c\uac1c\uc640 \uc21c\uc885\uc73c\ub85c \uc900\ube44\ub418\ub294 \uc0b6","\ub9c8\ud0dc\ubcf5\uc74c 3\uc7a5","\uc138\ub840 \uc694\ud55c\uc740 \uc720\ub300 \uad11\uc57c\uc5d0\uc11c \u201c\ud68c\uac1c\ud558\ub77c \ucc9c\uad6d\uc774 \uac00\uae4c\uc774 \uc654\ub2e4\u201d\uace0 \uc678\uce58\uba70 \uc0ac\ub78c\ub4e4\uc5d0\uac8c \ud558\ub098\ub2d8\uc758 \ub098\ub77c\ub97c \uc900\ube44\ud558\uac8c \ud588\uc5b4\uc694.\n\uadf8\ub294 \uc120\uc9c0\uc790 \uc774\uc0ac\uc57c\uac00 \uc608\uc5b8\ud55c \u201c\uc8fc\uc758 \uae38\uc744 \uc608\ube44\ud558\ub294 \uc790\u201d\ub85c\uc11c\uc758 \uc5ed\ud560\uc744 \ud558\uace0 \uc788\uc5c8\uc5b4\uc694.\n\ub9ce\uc740 \uc0ac\ub78c\ub4e4\uc774 \ub098\uc544\uc640 \uc790\uc2e0\uc758 \uc8c4\ub97c \uace0\ubc31\ud558\uace0 \uc694\ub2e8\uac15\uc5d0\uc11c \uc138\ub840\ub97c \ubc1b\uc558\uc5b4\uc694.\n\ud558\uc9c0\ub9cc \ubc14\ub9ac\uc0c8\uc778\uacfc \uc0ac\ub450\uac1c\uc778\ub4e4\uc774 \ud615\uc2dd\uc801\uc73c\ub85c \ub098\uc544\uc624\ub294 \uac83\uc744 \ubcf4\uace0 \uc694\ud55c\uc740 \uac15\ud558\uac8c \ucc45\ub9dd\ud588\uc5b4\uc694.\n\uadf8\ub294 \ub2e8\uc21c\ud55c \uc885\uad50\uc801 \ud589\ub3d9\uc774 \uc544\ub2c8\ub77c \uc0b6\uc758 \ubcc0\ud654, \uc989 \ud68c\uac1c\uc758 \uc5f4\ub9e4\ub97c \uac15\uc870\ud588\uc5b4\uc694.\n\ub610 \uc790\uc2e0\ubcf4\ub2e4 \ub354 \ud06c\uc2e0 \ubd84, \uace7 \uc608\uc218\ub2d8\uc774 \uc624\uc154\uc11c \uc131\ub839\uacfc \ubd88\ub85c \uc138\ub840\ub97c \uc8fc\uc2e4 \uac83\uc774\ub77c\uace0 \ub9d0\ud588\uc5b4\uc694.\n\uc774","\ub098\ub294 \uc9c4\uc9dc \ud68c\uac1c\ud558\uace0 \uc788\ub098\uc694?")
B.WB=new A.b5("matthew-lesson-5","path-matthew","\ub9d0\uc500\uc73c\ub85c \uc2dc\ud5d8\uc744 \uc774\uae30\uace0 \ubd80\ub974\uc2ec\uc5d0 \uc21c\uc885\ud558\ub294 \uc0b6","\ub9c8\ud0dc\ubcf5\uc74c 4\uc7a5","\uc608\uc218\ub2d8\uc740 \uacf5\uc0dd\uc560\ub97c \uc2dc\uc791\ud558\uc2dc\uae30 \uc804\uc5d0 \uad11\uc57c\uc5d0\uc11c \uc2dc\ud5d8\uc744 \ubc1b\uc73c\uc168\uc5b4\uc694. \ub9c8\uadc0\ub294 \uc721\uccb4\uc801 \uc695\uad6c, \ud558\ub098\ub2d8\uc744 \uc2dc\ud5d8\ud558\ub294 \ud0dc\ub3c4, \uc138\uc0c1\uc758 \uad8c\uc138\ub97c \uc81c\uc2dc\ud558\uba70 \uc608\uc218\ub2d8\uc744 \uc720\ud639\ud588\uc9c0\ub9cc, \uc608\uc218\ub2d8\uc740 \ubaa8\ub4e0 \uc2dc\ud5d8\uc744 \ud558\ub098\ub2d8\uc758 \ub9d0\uc500\uc73c\ub85c \uc774\uae30\uc168\uc5b4\uc694. \uc774\ud6c4 \uc608\uc218\ub2d8\uc740 \u201c\ud68c\uac1c\ud558\ub77c \ucc9c\uad6d\uc774 \uac00\uae4c\uc774 \uc654\ub290\ub2c8\ub77c\u201d\ub77c\uace0 \uc120\ud3ec\ud558\uc2dc\uba70 \uc0ac\uc5ed\uc744 \uc2dc\uc791\ud558\uc2dc\uace0, \uc81c\uc790\ub4e4\uc744 \ubd80\ub974\uc2e4 \ub54c \uadf8\ub4e4\uc740 \uc989\uc2dc \ubaa8\ub4e0 \uac83\uc744 \ub0b4\ub824\ub193\uace0 \ub530\ub790\uc5b4\uc694. \uc774 \uc7a5\uc740 \ud558\ub098\ub2d8\uc758 \ub9d0\uc500\uc73c\ub85c \uc720\ud639\uc744 \uc774\uae30\uace0, \ubd80\ub974\uc2ec \uc55e\uc5d0 \uc21c\uc885\ud558\ub294 \uc0b6\uc774 \ubb34\uc5c7\uc778\uc9c0 \ubcf4\uc5ec\uc918\uc694.","\ub098\ub294 \uc720\ud639 \uc55e\uc5d0\uc11c \ubb34\uc5c7\uc744 \uae30\uc900\uc73c\ub85c \uc120\ud0dd\ud558\uace0 \uc788\ub098\uc694?")
B.Xo=new A.b5("matthew-lesson-6","path-matthew","\ud558\ub098\ub2d8 \ub098\ub77c\uc758 \ubc31\uc131\uc774 \uc0b4\uc544\uac00\ub294 \uc0b6\uc758 \uae30\uc900","\ub9c8\ud0dc\ubcf5\uc74c 5\uc7a5","\uc608\uc218\ub2d8\uc740 \uc0b0 \uc704\uc5d0\uc11c \uc81c\uc790\ub4e4\uacfc \ubb34\ub9ac\uc5d0\uac8c \ud558\ub098\ub2d8 \ub098\ub77c\uc758 \uc0b6\uc758 \uae30\uc900\uc744 \uac00\ub974\uce58\uc168\uc5b4\uc694. \ud314\ubcf5\uc744 \ud1b5\ud574 \uc138\uc0c1\uc774 \uc544\ub2cc \ud558\ub098\ub2d8 \uae30\uc900\uc5d0\uc11c\uc758 \ubcf5\uc744 \uc124\uba85\ud558\uc2dc\uace0, \uc81c\uc790\ub4e4\uc774 \uc138\uc0c1\uc758 \ube5b\uacfc \uc18c\uae08\uc73c\ub85c \uc0b4\uc544\uac00\uc57c \ud55c\ub2e4\uace0 \ub9d0\uc500\ud558\uc168\uc5b4\uc694. \ub610\ud55c \uc728\ubc95\uc744 \ud3d0\ud558\ub7ec \uc624\uc2e0 \uac83\uc774 \uc544\ub2c8\ub77c \uc644\uc804\ud558\uac8c \ud558\ub7ec \uc624\uc168\ub2e4\uace0 \ud558\uc2dc\uba70, \ubd84\ub178, \uc74c\uc695, \ub9f9\uc138, \ubcf5\uc218 \ub4f1 \ub9c8\uc74c\uc758 \uc0c1\ud0dc\uae4c\uc9c0 \ud3ec\ud568\ud55c \ub354 \uae4a\uc740 \uc758\ub97c \uc694\uad6c\ud558\uc168\uc5b4\uc694. \ub9c8\uc9c0\ub9c9\uc73c\ub85c \uc6d0\uc218\ub97c \uc0ac\ub791\ud558\ub77c\ub294 \ub9d0\uc500\uc744 \ud1b5\ud574 \ud558\ub098\ub2d8 \ub098\ub77c\uc758 \uc0ac\ub791\uc774 \uc5b4\ub5a4 \uac83\uc778\uc9c0 \ubcf4\uc5ec\uc8fc\uc168\uc5b4\uc694. \uc774 \uc7a5\uc740 \uac89\uc73c\ub85c \ubcf4\uc774\ub294 \ud589\ub3d9\uc774 \uc544\ub2c8\ub77c \ub9c8\uc74c\uae4c\uc9c0 \ud3ec\ud568\ud55c \uc9c4\uc9dc \uc758\ub85c\uc6b4 \uc0b6\uc774 \ubb34\uc5c7\uc778\uc9c0 \uac00\ub974\uccd0\uc918\uc694.","\ub098\ub294 \uc138\uc0c1\uc758 \uae30\uc900\uc774 \uc544\ub2cc \ud558\ub098\ub2d8 \uae30\uc900\uc73c\ub85c \uc0b4\uace0 \uc788\ub098\uc694?")
B.WE=new A.b5("matthew-lesson-7","path-matthew","\ud558\ub098\ub2d8 \uc55e\uc5d0\uc11c\uc758 \uc9c4\uc9dc \uacbd\uac74\uacfc \uc0b6\uc758 \uc6b0\uc120\uc21c\uc704","\ub9c8\ud0dc\ubcf5\uc74c 6\uc7a5","\uc608\uc218\ub2d8\uc740 \uad6c\uc81c, \uae30\ub3c4, \uae08\uc2dd\uacfc \uac19\uc740 \uacbd\uac74\ud55c \ud589\ub3d9\uc744 \uc0ac\ub78c\uc5d0\uac8c \ubcf4\uc774\uae30 \uc704\ud55c \uac83\uc774 \uc544\ub2c8\ub77c \ud558\ub098\ub2d8 \uc55e\uc5d0\uc11c \ud574\uc57c \ud55c\ub2e4\uace0 \uac00\ub974\uce58\uc168\uc5b4\uc694. \uc8fc\uae30\ub3c4\ubb38\uc744 \ud1b5\ud574 \ud558\ub098\ub2d8\uacfc\uc758 \uc62c\ubc14\ub978 \uad00\uacc4\uc640 \uae30\ub3c4\uc758 \ubc29\ud5a5\uc744 \uc54c\ub824\uc8fc\uc2dc\uace0, \uc7ac\ubb3c\uc5d0 \ub300\ud55c \ud0dc\ub3c4\uc640 \uc5fc\ub824\ud558\uc9c0 \ub9d0\ub77c\ub294 \uac00\ub974\uce68\uc744 \ud1b5\ud574 \uc0b6\uc758 \uc6b0\uc120\uc21c\uc704\ub97c \ubc14\ub85c \uc138\uc6b0\ub77c\uace0 \ud558\uc168\uc5b4\uc694. \ud558\ub098\ub2d8 \ub098\ub77c\uc640 \uc758\ub97c \uba3c\uc800 \uad6c\ud560 \ub54c \ud544\uc694\ud55c \uac83\uc744 \ud558\ub098\ub2d8\uc774 \ucc44\uc6cc\uc8fc\uc2e0\ub2e4\uace0 \ub9d0\uc500\ud558\uc138\uc694.","\ub098\ub294 \ud558\ub098\ub2d8\uc774 \uc544\ub2c8\ub77c \uc0ac\ub78c\uc744 \uc758\uc2dd\ud558\uba70 \uc0b4\uace0 \uc788\ub098\uc694?")
B.WS=new A.b5("matthew-lesson-8","path-matthew","\ucc38\ub41c \uc81c\uc790\uc758 \uc0b6\uacfc \uc120\ud0dd","\ub9c8\ud0dc\ubcf5\uc74c 7\uc7a5","\uc608\uc218\ub2d8\uc740 \ub2e4\ub978 \uc0ac\ub78c\uc744 \ud310\ub2e8\ud558\uae30 \uc804\uc5d0 \uc790\uc2e0\uc744 \ub3cc\uc544\ubcf4\ub77c\uace0 \ud558\uc2dc\uba70, \uad6c\ud558\uace0 \ucc3e\uace0 \ub450\ub4dc\ub9ac\ub77c\ub294 \ubbff\uc74c\uc758 \ud0dc\ub3c4\ub97c \uac00\ub974\uce58\uc168\uc5b4\uc694. \uc881\uc740 \uae38\uacfc \ub113\uc740 \uae38\uc758 \ube44\uc720\ub97c \ud1b5\ud574 \uc0dd\uba85\uc73c\ub85c \uac00\ub294 \uae38\uc740 \uc27d\uc9c0 \uc54a\uc9c0\ub9cc \ubd84\uba85\ud788 \uc874\uc7ac\ud55c\ub2e4\uace0 \ub9d0\uc500\ud558\uc2dc\uace0, \uc5f4\ub9e4\ub85c \uc0ac\ub78c\uc744 \uc54c \uc218 \uc788\ub2e4\uace0 \ud558\uc168\uc5b4\uc694. \ub9c8\uc9c0\ub9c9\uc73c\ub85c \ub9d0\uc500\uc744 \ub4e3\uace0 \ud589\ud558\ub294 \uc790\uc640 \uadf8\ub807\uc9c0 \uc54a\uc740 \uc790\ub97c \ubc18\uc11d\uacfc \ubaa8\ub798 \uc704\uc758 \uc9d1\uc73c\ub85c \ube44\uc720\ud558\uba70 \uc0b6\uc758 \uae30\ucd08\uac00 \ubb34\uc5c7\uc778\uc9c0 \uac15\uc870\ud558\uc138\uc694.","\ub098\ub294 \ub9d0\uc500\uc744 \ub4e3\ub294 \uac83\uc5d0\uc11c \ub05d\ub098\uace0 \uc788\ub098\uc694, \uc544\ub2c8\uba74 \uc2e4\ucc9c\ud558\uace0 \uc788\ub098\uc694?")
B.X6=new A.b5("matthew-lesson-9","path-matthew","\uc608\uc218\ub2d8\uc758 \uad8c\uc704\uc640 \ubbff\uc74c","\ub9c8\ud0dc\ubcf5\uc74c 8\uc7a5","\uc608\uc218\ub2d8\uc740 \ub098\ubcd1\ud658\uc790, \ubc31\ubd80\uc7a5\uc758 \uc885, \ubca0\ub4dc\ub85c\uc758 \uc7a5\ubaa8 \ub4f1\uc744 \uace0\uce58\uc2dc\uba70 \ubcd1\uacfc \uace0\ud1b5 \uc704\uc5d0 \uad8c\uc138\uac00 \uc788\uc73c\uc2ec\uc744 \ubcf4\uc5ec\uc8fc\uc168\uc5b4\uc694. \ud2b9\ud788 \ubc31\ubd80\uc7a5\uc740 \ub9d0\uc500\ub9cc\uc73c\ub85c\ub3c4 \uce58\uc720\ud558\uc2e4 \uc218 \uc788\ub2e4\ub294 \ubbff\uc74c\uc744 \ubcf4\uc5ec\uc8fc\uba70 \uce6d\ucc2c\uc744 \ubc1b\uc558\uc5b4\uc694. \ub610\ud55c \ubc14\ub78c\uacfc \ubc14\ub2e4\ub97c \uc7a0\uc7a0\ud558\uac8c \ud558\uc2dc\uba70 \uc790\uc5f0\uae4c\uc9c0 \ub2e4\uc2a4\ub9ac\ub294 \uad8c\uc704\ub97c \ub098\ud0c0\ub0b4\uc168\uc5b4\uc694.","\ub098\ub294 \uc608\uc218\ub2d8\uc758 \uad8c\uc704\ub97c \uc5bc\ub9c8\ub098 \uc2e0\ub8b0\ud558\uace0 \uc788\ub098\uc694?")
B.XA=new A.b5("matthew-lesson-10","path-matthew","\uc8c4\ub97c \uc0ac\ud558\uc2dc\uace0 \uc0ac\ub78c\uc744 \ubd80\ub974\uc2dc\ub294 \uc608\uc218\ub2d8","\ub9c8\ud0dc\ubcf5\uc74c 9\uc7a5","\uc608\uc218\ub2d8\uc740 \uc911\ud48d\ubcd1\uc790\uc758 \uc8c4\ub97c \uba3c\uc800 \uc0ac\ud558\uc2dc\uace0 \ubcd1\uc744 \uace0\uce58\uc2dc\uba70 \uc601\uc801 \uad8c\uc704\ub97c \ub098\ud0c0\ub0b4\uc168\uc5b4\uc694. \uc138\ub9ac \ub9c8\ud0dc\ub97c \ubd80\ub974\uc2dc\uba70 \uc8c4\uc778\uc744 \ud5a5\ud55c \ubd80\ub974\uc2ec\uc744 \ubcf4\uc5ec\uc8fc\uc2dc\uace0, \uae08\uc2dd\uacfc \uc0c8 \ud3ec\ub3c4\uc8fc\uc758 \ube44\uc720\ub97c \ud1b5\ud574 \uc0c8\ub85c\uc6b4 \uc2dc\ub300\ub97c \uc124\uba85\ud558\uc168\uc5b4\uc694. \ub610\ud55c \ub9ce\uc740 \ubcd1\uc790\ub97c \uace0\uce58\uc2dc\uba70 \ubb34\ub9ac\ub97c \ubd88\uc30d\ud788 \uc5ec\uae30\uc168\uc5b4\uc694.","\ub098\ub294 \uc608\uc218\ub2d8\uc758 \ubd80\ub974\uc2ec\uc5d0 \uc751\ub2f5\ud558\uace0 \uc788\ub098\uc694?")
B.Xu=new A.b5("matthew-lesson-11","path-matthew","\uc81c\uc790\uc758 \uc0ac\uba85\uacfc \ub300\uac00","\ub9c8\ud0dc\ubcf5\uc74c 10\uc7a5","\uc608\uc218\ub2d8\uc740 \uc5f4\ub450 \uc81c\uc790\ub97c \ubd80\ub974\uc2dc\uace0 \ubcf5\uc74c\uc744 \uc804\ud558\ub3c4\ub85d \ubcf4\ub0b4\uc168\uc5b4\uc694. \ubcd1\uc744 \uace0\uce58\uace0 \uadc0\uc2e0\uc744 \ucad3\ub294 \uad8c\uc138\ub3c4 \uc8fc\uc168\uc9c0\ub9cc, \ub3d9\uc2dc\uc5d0 \ud54d\ubc15\uacfc \uc5b4\ub824\uc6c0\ub3c4 \ud568\uaed8 \uc788\uc744 \uac83\uc744 \ub9d0\uc500\ud558\uc168\uc5b4\uc694. \uc0ac\ub78c\uc744 \ub450\ub824\uc6cc\ud558\uc9c0 \ub9d0\uace0 \ud558\ub098\ub2d8\uc744 \ub450\ub824\uc6cc\ud558\ub77c\uace0 \ud558\uc2dc\uba70, \uc608\uc218\ub2d8\uc744 \ub530\ub974\ub294 \uac83\uc740 \uad00\uacc4\uc640 \uc0b6\uc758 \uc6b0\uc120\uc21c\uc704\uae4c\uc9c0 \ubc14\uafb8\ub294 \uacb0\ub2e8\uc774 \ud544\uc694\ud558\ub2e4\uace0 \uac00\ub974\uce58\uc168\uc5b4\uc694.","\ub098\ub294 \ubcf5\uc74c\uc744 \uc804\ud558\ub294 \uc0b6\uc744 \uc0b4\uace0 \uc788\ub098\uc694?")
B.Xe=new A.b5("matthew-lesson-12","path-matthew","\uc608\uc218\ub2d8\uc744 \ud5a5\ud55c \ubc18\uc751\uacfc \ucc38\ub41c \uc27c","\ub9c8\ud0dc\ubcf5\uc74c 11\uc7a5","\uc138\ub840 \uc694\ud55c\uc740 \uac10\uc625\uc5d0\uc11c \uc608\uc218\ub2d8\uc774 \uba54\uc2dc\uc544\uc778\uc9c0 \uc9c8\ubb38\ud558\uace0, \uc608\uc218\ub2d8\uc740 \uc790\uc2e0\uc758 \uc0ac\uc5ed\uc73c\ub85c \ub2f5\ud558\uc138\uc694. \uc608\uc218\ub2d8\uc740 \ud68c\uac1c\ud558\uc9c0 \uc54a\ub294 \ub3c4\uc2dc\ub4e4\uc744 \ucc45\ub9dd\ud558\uc2dc\uace0, \uc5b4\ub9b0\uc544\uc774\uc640 \uac19\uc740 \uc790\uc5d0\uac8c \ud558\ub098\ub2d8\uc758 \uc77c\uc774 \ub4dc\ub7ec\ub09c\ub2e4\uace0 \ub9d0\uc500\ud558\uc138\uc694. \ub9c8\uc9c0\ub9c9\uc5d0\ub294 \u201c\uc218\uace0\ud558\uace0 \ubb34\uac70\uc6b4 \uc9d0 \uc9c4 \uc790\ub4e4\uc544 \ub2e4 \ub0b4\uac8c\ub85c \uc624\ub77c\u201d \ud558\uc2dc\uba70 \ucc38\ub41c \uc27c\uc744 \uc57d\uc18d\ud558\uc138\uc694.","\ub098\ub294 \uc608\uc218\ub2d8\uc744 \uc758\uc2ec\ud558\uace0 \uc788\ub098\uc694, \uc2e0\ub8b0\ud558\uace0 \uc788\ub098\uc694?")
B.Xt=new A.b5("matthew-lesson-13","path-matthew","\ucc38\ub41c \uc548\uc2dd\uacfc \ub9c8\uc74c\uc758 \uc0c1\ud0dc","\ub9c8\ud0dc\ubcf5\uc74c 12\uc7a5","\uc608\uc218\ub2d8\uc740 \uc548\uc2dd\uc77c\uc758 \uc8fc\uc778\uc774\uc2ec\uc744 \uc120\uc5b8\ud558\uc2dc\uba70 \ud615\uc2dd\ubcf4\ub2e4 \uc0ac\ub78c\uc744 \uc0b4\ub9ac\ub294 \uac83\uc774 \uc911\uc694\ud558\ub2e4\uace0 \uac00\ub974\uce58\uc168\uc5b4\uc694. \ub610\ud55c \uadc0\uc2e0\uc744 \ucad3\uc544\ub0b4\uc2dc\uba70 \ud558\ub098\ub2d8\uc758 \ub098\ub77c\uac00 \uc784\ud588\uc74c\uc744 \ubcf4\uc5ec\uc8fc\uc2dc\uace0, \ub9c8\uc74c\uc5d0\uc11c \ub098\uc624\ub294 \uac83\uc774 \uc0ac\ub78c\uc744 \ub354\ub7fd\uac8c \ud55c\ub2e4\uace0 \ub9d0\uc500\ud558\uc138\uc694.","\ub098\ub294 \ud615\uc2dd\uc801\uc778 \uc2e0\uc559\uc5d0 \uba38\ubb3c\ub7ec \uc788\ub098\uc694?")
B.Xv=new A.b5("matthew-lesson-14","path-matthew","\ud558\ub098\ub2d8 \ub098\ub77c\ub97c \ubc1b\uc544\ub4e4\uc774\ub294 \ub9c8\uc74c","\ub9c8\ud0dc\ubcf5\uc74c 13\uc7a5","\uc608\uc218\ub2d8\uc740 \uc528 \ubfcc\ub9ac\ub294 \ube44\uc720\ub97c \ud1b5\ud574 \uc0ac\ub78c\uc758 \ub9c8\uc74c \uc0c1\ud0dc\uc5d0 \ub530\ub77c \ub9d0\uc500\uc774 \ub2e4\ub974\uac8c \ubc1b\uc544\ub4e4\uc5ec\uc9c4\ub2e4\uace0 \uac00\ub974\uce58\uc168\uc5b4\uc694. \uc88b\uc740 \ub545\uc5d0 \ubfcc\ub824\uc9c4 \uc528\ub294 \uc5f4\ub9e4\ub97c \ub9fa\uc9c0\ub9cc, \uadf8\ub807\uc9c0 \uc54a\uc740 \ub9c8\uc74c\uc740 \uc5f4\ub9e4\ub97c \ub9fa\uc9c0 \ubabb\ud574\uc694. \uc5ec\ub7ec \ube44\uc720\ub97c \ud1b5\ud574 \ud558\ub098\ub2d8 \ub098\ub77c\uc758 \uac00\uce58\uc640 \ud2b9\uc9d5\uc744 \uc124\uba85\ud558\uc138\uc694.","\ub098\ub294 \uc5b4\ub5a4 \ub9c8\uc74c \uc0c1\ud0dc\ub85c \ub9d0\uc500\uc744 \ub4e3\uace0 \uc788\ub098\uc694?")
B.X5=new A.b5("matthew-lesson-15","path-matthew","\ubbff\uc74c\uacfc \uc2dc\uc120","\ub9c8\ud0dc\ubcf5\uc74c 14\uc7a5","\uc138\ub840 \uc694\ud55c\uc774 \uc8fd\uc784\uc744 \ub2f9\ud55c \ud6c4 \uc608\uc218\ub2d8\uc740 \ubb34\ub9ac\ub97c \ubd88\uc30d\ud788 \uc5ec\uae30\uc2dc\uace0 \uc624\ubcd1\uc774\uc5b4\ub85c \uba39\uc774\uc168\uc5b4\uc694. \uc774\ud6c4 \uc81c\uc790\ub4e4\uc774 \ubc30\ub97c \ud0c0\uace0 \uac08 \ub54c \uc608\uc218\ub2d8\uc774 \ubb3c \uc704\ub97c \uac78\uc5b4\uc624\uc2dc\uace0, \ubca0\ub4dc\ub85c\ub3c4 \ubbff\uc74c\uc73c\ub85c \uac78\uc5c8\uc9c0\ub9cc \ubc14\ub78c\uc744 \ubcf4\uace0 \ub450\ub824\uc6cc \ube60\uc9c0\uac8c \ub3fc\uc694. \uc774 \uc7a5\uc740 \uc608\uc218\ub2d8\uc744 \ubc14\ub77c\ubcfc \ub54c\uc640 \uc0c1\ud669\uc744 \ubc14\ub77c\ubcfc \ub54c\uc758 \ucc28\uc774\ub97c \ubcf4\uc5ec\uc918\uc694.","\ub098\ub294 \uc0c1\ud669\uc774 \uc544\ub2c8\ub77c \uc608\uc218\ub2d8\uc744 \ubc14\ub77c\ubcf4\uace0 \uc788\ub098\uc694?")
B.Wt=new A.b5("matthew-lesson-16","path-matthew","\ub9c8\uc74c\uc5d0\uc11c \ub098\uc624\ub294 \uc2e0\uc559","\ub9c8\ud0dc\ubcf5\uc74c 15\uc7a5","\uc608\uc218\ub2d8\uc740 \uc0ac\ub78c\uc744 \ub354\ub7fd\uac8c \ud558\ub294 \uac83\uc740 \uc678\uc801\uc778 \uac83\uc774 \uc544\ub2c8\ub77c \ub9c8\uc74c\uc5d0\uc11c \ub098\uc624\ub294 \uac83\uc774\ub77c\uace0 \ub9d0\uc500\ud558\uc168\uc5b4\uc694. \ub610\ud55c \uac00\ub098\uc548 \uc5ec\uc778\uc758 \ubbff\uc74c\uc744 \ud1b5\ud574 \uc9c4\uc9dc \ubbff\uc74c\uc774 \ubb34\uc5c7\uc778\uc9c0 \ubcf4\uc5ec\uc8fc\uc2dc\uace0, \ub9ce\uc740 \ubcd1\uc790\ub97c \uace0\uce58\uba70 \uae0d\ud73c\uc744 \ubca0\ud478\uc168\uc5b4\uc694.","\ub098\ub294 \uac89\uc774 \uc544\ub2c8\ub77c \ub9c8\uc74c\uc774 \ud558\ub098\ub2d8\uaed8 \ud5a5\ud574 \uc788\ub098\uc694?")
B.Xg=new A.b5("matthew-lesson-17","path-matthew","\uc608\uc218\ub2d8\uc758 \uc815\uccb4\uc131\uacfc \uc81c\uc790\uc758 \uae38","\ub9c8\ud0dc\ubcf5\uc74c 16\uc7a5","\ubca0\ub4dc\ub85c\ub294 \uc608\uc218\ub2d8\uc744 \u201c\uadf8\ub9ac\uc2a4\ub3c4, \uc0b4\uc544\uacc4\uc2e0 \ud558\ub098\ub2d8\uc758 \uc544\ub4e4\u201d\uc774\ub77c\uace0 \uace0\ubc31\ud574\uc694. \uc608\uc218\ub2d8\uc740 \uc790\uc2e0\uc774 \uace0\ub09c\ubc1b\uace0 \uc8fd\uc73c\uc2e4 \uac83\uc744 \uc608\uace0\ud558\uc2dc\uace0, \uc81c\uc790\ub294 \uc790\uae30 \uc2ed\uc790\uac00\ub97c \uc9c0\uace0 \ub530\ub77c\uc57c \ud55c\ub2e4\uace0 \ub9d0\uc500\ud558\uc138\uc694.","\ub098\ub294 \uc608\uc218\ub2d8\uc744 \ub204\uad6c\ub77c\uace0 \uace0\ubc31\ud558\uace0 \uc788\ub098\uc694?")
B.XC=new A.b5("matthew-lesson-18","path-matthew","\ud558\ub098\ub2d8\uc758 \uc601\uad11\uacfc \ubbff\uc74c","\ub9c8\ud0dc\ubcf5\uc74c 17\uc7a5","\uc608\uc218\ub2d8\uc740 \ubcc0\ud654\uc0b0\uc5d0\uc11c \uc601\uad11\uc2a4\ub7ec\uc6b4 \ubaa8\uc2b5\uc744 \ubcf4\uc774\uc2dc\uace0 \ud558\ub098\ub2d8\uc758 \uc74c\uc131\uc774 \ub4e4\ub824\uc694. \uc774\ud6c4 \uc81c\uc790\ub4e4\uc774 \uadc0\uc2e0 \ub4e4\ub9b0 \uc544\uc774\ub97c \uace0\uce58\uc9c0 \ubabb\ud558\uc790 \ubbff\uc74c\uc758 \ubd80\uc871\uc744 \uc9c0\uc801\ud558\uc2dc\uba70 \ubbff\uc74c\uc758 \uc911\uc694\uc131\uc744 \ub9d0\uc500\ud558\uc138\uc694.","\ub098\ub294 \ud558\ub098\ub2d8\uc744 \uc5bc\ub9c8\ub098 \ud06c\uac8c \ubcf4\uace0 \uc788\ub098\uc694?")
B.XG=new A.b5("matthew-lesson-19","path-matthew","\uacb8\uc190\uacfc \uc6a9\uc11c\uc758 \uacf5\ub3d9\uccb4","\ub9c8\ud0dc\ubcf5\uc74c 18\uc7a5","\uc81c\uc790\ub4e4\uc774 \ub204\uac00 \ud070 \uc790\uc778\uc9c0 \ubb3b\uc790 \uc608\uc218\ub2d8\uc740 \uc5b4\ub9b0\uc544\uc774\ub97c \uc138\uc6b0\uc2dc\uba70 \ub0ae\uc544\uc9c0\ub294 \uc0ac\ub78c\uc774 \ud558\ub098\ub2d8 \ub098\ub77c\uc5d0\uc11c \ud070 \uc790\ub77c\uace0 \ub9d0\uc500\ud558\uc168\uc5b4\uc694. \ub610\ud55c \ud55c \uc601\ud63c\uc758 \uc18c\uc911\ud568\uc744 \uac15\uc870\ud558\uc2dc\uba70 \uc783\uc740 \uc591 \ud55c \ub9c8\ub9ac\ub97c \ub05d\uae4c\uc9c0 \ucc3e\uc73c\uc2dc\ub294 \ud558\ub098\ub2d8\uc758 \ub9c8\uc74c\uc744 \ubcf4\uc5ec\uc8fc\uc168\uc5b4\uc694. \ud615\uc81c\uac00 \uc8c4\ub97c \uc9c0\uc5c8\uc744 \ub54c\ub294 \ubb34\uc870\uac74 \ud310\ub2e8\ud558\uae30\ubcf4\ub2e4 \ud68c\ubcf5\uc744 \uc704\ud55c \uacfc\uc815\uc774 \ud544\uc694\ud558\ub2e4\uace0 \uac00\ub974\uce58\uc168\uc5b4\uc694. \uadf8\ub9ac\uace0 \uc6a9\uc11c\ub294 \ud55c\ub450 \ubc88\uc774 \uc544\ub2c8\ub77c \uacc4\uc18d\ud574\uc57c \ud55c\ub2e4\uace0 \ub9d0\uc500\ud558\uc2dc\uba70, \uc77c\ub9cc \ub2ec\ub780\ud2b8 \ube5a\uc9c4 \uc790\uc758 \ube44\uc720\ub97c \ud1b5\ud574 \ubc1b\uc740 \uc740\ud61c\ub9cc\ud07c \uc6a9\uc11c\ud574\uc57c \ud568\uc744 \uac15\uc870\ud558\uc138\uc694. \uc774 \uc7a5\uc740 \ud558\ub098\ub2d8 \ub098\ub77c \uacf5\ub3d9\uccb4\uac00 \uc5b4\ub5a4 \ud0dc\ub3c4\ub85c \uc11c\ub85c\ub97c \ub300\ud574\uc57c \ud558\ub294\uc9c0\ub97c \ubcf4\uc5ec\uc918\uc694.","\ub098\ub294 \ub0ae\uc544\uc9c0\ub294 \uc0b6\uc744 \uc0b4\uace0 \uc788\ub098\uc694?")
B.WF=new A.b5("matthew-lesson-20","path-matthew","\ud558\ub098\ub2d8 \ub098\ub77c\uc758 \uac00\uce58\uc640 \uacb0\ub2e8","\ub9c8\ud0dc\ubcf5\uc74c 19\uc7a5","\uc608\uc218\ub2d8\uc740 \uacb0\ud63c\uacfc \uc774\ud63c\uc5d0 \ub300\ud574 \ub9d0\uc500\ud558\uc2dc\uba70 \ud558\ub098\ub2d8\uc774 \ucc98\uc74c \ub9cc\ub4dc\uc2e0 \uad00\uacc4\uc758 \uc758\ubbf8\ub97c \ud68c\ubcf5\uc2dc\ud0a4\uc168\uc5b4\uc694. \ub610\ud55c \uc5b4\ub9b0\uc544\uc774\uc640 \uac19\uc740 \uc790\uac00 \ud558\ub098\ub2d8 \ub098\ub77c\uc5d0 \ub4e4\uc5b4\uac04\ub2e4\uace0 \ud558\uc2dc\uba70 \uacb8\uc190\uacfc \uc758\uc874\uc758 \ud0dc\ub3c4\ub97c \uac15\uc870\ud558\uc168\uc5b4\uc694. \ubd80\uc790 \uccad\ub144\uc740 \uc608\uc218\ub2d8\uc758 \ub9d0\uc500\uc744 \ub4e3\uace0\ub3c4 \uc7ac\ubb3c\uc744 \ub0b4\ub824\ub193\uc9c0 \ubabb\ud558\uace0 \ub5a0\ub098\uc694. \uc774\ub97c \ud1b5\ud574 \ud558\ub098\ub2d8\uc744 \ub530\ub974\ub294 \uc0b6\uc740 \ub2e8\uc21c\ud55c \ubbff\uc74c\uc774 \uc544\ub2c8\ub77c \uc2e4\uc81c\uc801\uc778 \uacb0\ub2e8\uc774 \ud544\uc694\ud568\uc744 \ubcf4\uc5ec\uc918\uc694. \uc774 \uc7a5\uc740 \ud558\ub098\ub2d8 \ub098\ub77c\ub97c \ub530\ub974\uae30 \uc704\ud574 \ubb34\uc5c7\uc744 \ub0b4\ub824\ub193\uc544\uc57c \ud558\ub294\uc9c0\ub97c \uc9c8\ubb38\ud558\uac8c \ud574\uc694.","\ub098\ub294 \ud558\ub098\ub2d8\ubcf4\ub2e4 \ub354 \ubd99\uc7a1\uace0 \uc788\ub294 \uac83\uc774 \uc788\ub098\uc694?")
B.XD=new A.b5("matthew-lesson-21","path-matthew","\uc740\ud61c\uc640 \uc12c\uae40\uc758 \uc6d0\ub9ac","\ub9c8\ud0dc\ubcf5\uc74c 20\uc7a5","\ud3ec\ub3c4\uc6d0 \ud488\uafbc\uc758 \ube44\uc720\uc5d0\uc11c \ud558\ub098\ub2d8\uc740 \uc77c\ud55c \uc2dc\uac04\uacfc \uc0c1\uad00\uc5c6\uc774 \ub3d9\uc77c\ud55c \ud488\uc0af\uc744 \uc8fc\uc168\uc5b4\uc694. \uc774\ub294 \ud558\ub098\ub2d8\uc758 \uc740\ud61c\uac00 \uacf5\ub85c\uac00 \uc544\ub2c8\ub77c \uc120\ubb3c\uc774\ub77c\ub294 \uac83\uc744 \ubcf4\uc5ec\uc918\uc694. \uc608\uc218\ub2d8\uc740 \uc790\uc2e0\uc758 \uace0\ub09c\uc744 \uc608\uace0\ud558\uc2dc\uba70 \uc81c\uc790\ub4e4\uc5d0\uac8c \uc12c\uae40\uc758 \uae38\uc744 \uac00\ub974\uce58\uc168\uc5b4\uc694. \ud558\ub098\ub2d8 \ub098\ub77c\uc5d0\uc11c\ub294 \ub192\uc544\uc9c0\ub294 \uac83\uc774 \uc544\ub2c8\ub77c \ub0ae\uc544\uc838 \uc12c\uae30\ub294 \uc0ac\ub78c\uc774 \ud070 \uc790\ub77c\uace0 \ub9d0\uc500\ud558\uc138\uc694. \uc774 \uc7a5\uc740 \ube44\uad50\uc640 \uacbd\uc7c1\uc774 \uc544\ub2c8\ub77c \uc740\ud61c\uc640 \uc12c\uae40\uc774 \uc911\uc2ec\uc774 \ub418\ub294 \uc0b6\uc744 \ubcf4\uc5ec\uc918\uc694.","\ub098\ub294 \ud558\ub098\ub2d8\uc758 \uc740\ud61c\ub97c \ub2f9\uc5f0\ud558\uac8c \uc5ec\uae30\uace0 \uc788\ub098\uc694?")
B.WJ=new A.b5("matthew-lesson-22","path-matthew","\uc655\uc73c\ub85c \uc624\uc2e0 \uc608\uc218\ub2d8\uacfc \uc5f4\ub9e4","\ub9c8\ud0dc\ubcf5\uc74c 21\uc7a5","\uc608\uc218\ub2d8\uc740 \uc608\ub8e8\uc0b4\ub818\uc5d0 \uacb8\uc190\ud55c \uc655\uc73c\ub85c \uc785\uc131\ud558\uc2dc\uba70 \uba54\uc2dc\uc544\uc774\uc2ec\uc744 \ub4dc\ub7ec\ub0b4\uc168\uc5b4\uc694. \uc131\uc804\uc744 \uae68\ub057\ud558\uac8c \ud558\uc2dc\uba70 \ud558\ub098\ub2d8\uc744 \uc608\ubc30\ud558\ub294 \uacf3\uc774 \uc0ac\ub78c\uc758 \uc695\uc2ec\uc73c\ub85c \ub354\ub7fd\ud600\uc9c4 \uac83\uc744 \ucc45\ub9dd\ud558\uc168\uc5b4\uc694. \ubb34\ud654\uacfc\ub098\ubb34\ub97c \uc800\uc8fc\ud558\uc2e0 \uc0ac\uac74\uc744 \ud1b5\ud574 \uac89\ubaa8\uc2b5\uc740 \uc788\uc73c\ub098 \uc5f4\ub9e4 \uc5c6\ub294 \uc2e0\uc559\uc744 \uacbd\uace0\ud558\uc168\uc5b4\uc694. \ub450 \uc544\ub4e4\uacfc \uc545\ud55c \ub18d\ubd80\uc758 \ube44\uc720\ub85c \ub9d0\uacfc \ud589\ub3d9\uc774 \ub2e4\ub978 \uc2e0\uc559\uacfc \ucc45\uc784\uc744 \uac15\uc870\ud558\uc168\uc5b4\uc694. \uc774 \uc7a5\uc740 \ud558\ub098\ub2d8 \uc55e\uc5d0\uc11c \uc2e4\uc81c \uc5f4\ub9e4\uac00 \uc788\ub294 \uc0b6\uc774 \ubb34\uc5c7\uc778\uc9c0 \ubcf4\uc5ec\uc918\uc694.","\ub098\ub294 \uc5f4\ub9e4 \uc788\ub294 \uc0b6\uc744 \uc0b4\uace0 \uc788\ub098\uc694?")
B.X3=new A.b5("matthew-lesson-23","path-matthew","\ud558\ub098\ub2d8 \ub098\ub77c\uc758 \ucd08\ub300\uc640 \uc0ac\ub791\uc758 \uacc4\uba85","\ub9c8\ud0dc\ubcf5\uc74c 22\uc7a5","\ud63c\uc778\uc794\uce58 \ube44\uc720\ub97c \ud1b5\ud574 \ud558\ub098\ub2d8 \ub098\ub77c\uc5d0 \ucd08\ub300\ubc1b\uc740 \uc0ac\ub78c\ub4e4\uc758 \ub2e4\uc591\ud55c \ubc18\uc751\uc744 \ubcf4\uc5ec\uc8fc\uc138\uc694. \ucd08\ub300\ub97c \uac70\uc808\ud55c \uc0ac\ub78c\ub4e4\uacfc \uc900\ube44\ub418\uc9c0 \uc54a\uc740 \uc0ac\ub78c\uc740 \uacb0\uad6d \ucc38\uc5ec\ud558\uc9c0 \ubabb\ud574\uc694. \uc608\uc218\ub2d8\uc740 \uac00\uc774\uc0ac\uc758 \uac83\uacfc \ud558\ub098\ub2d8\uc758 \uac83\uc744 \uad6c\ubd84\ud558\uba70 \uc0b6\uc758 \uae30\uc900\uc744 \ubc14\ub85c \uc138\uc6b0\uc168\uc5b4\uc694. \uac00\uc7a5 \ud070 \uacc4\uba85\uc73c\ub85c \ud558\ub098\ub2d8 \uc0ac\ub791\uacfc \uc774\uc6c3 \uc0ac\ub791\uc744 \ub9d0\uc500\ud558\uc2dc\uba70 \uc2e0\uc559\uc758 \ud575\uc2ec\uc744 \uc815\ub9ac\ud558\uc138\uc694. \uc774 \uc7a5\uc740 \ud558\ub098\ub2d8 \ub098\ub77c\uc5d0 \ud569\ub2f9\ud55c \uc0b6\uc774 \ubb34\uc5c7\uc778\uc9c0 \ubd84\uba85\ud788 \ubcf4\uc5ec\uc918\uc694.","\ub098\ub294 \ud558\ub098\ub2d8 \ub098\ub77c\uc5d0 \uc900\ube44\ub41c \uc0b6\uc744 \uc0b4\uace0 \uc788\ub098\uc694?")
B.Xp=new A.b5("matthew-lesson-24","path-matthew","\uc678\uc2dd\uc774 \uc544\ub2cc \ucc38\ub41c \uc2e0\uc559","\ub9c8\ud0dc\ubcf5\uc74c 23\uc7a5","\uc608\uc218\ub2d8\uc740 \uc11c\uae30\uad00\uacfc \ubc14\ub9ac\uc0c8\uc778\uc758 \uc678\uc2dd\uc744 \uac15\ud558\uac8c \ucc45\ub9dd\ud558\uc168\uc5b4\uc694. \uadf8\ub4e4\uc740 \uac89\uc73c\ub85c\ub294 \uacbd\uac74\ud574 \ubcf4\uc600\uc9c0\ub9cc \ub9c8\uc74c\uc740 \ud558\ub098\ub2d8\uacfc \uba40\uc5b4\uc838 \uc788\uc5c8\uc5b4\uc694. \uc0ac\ub78c\uc5d0\uac8c \ubcf4\uc774\uae30 \uc704\ud55c \ud589\ub3d9\uacfc \uc704\uc120\uc801\uc778 \ud0dc\ub3c4\ub97c \uc9c0\uc801\ud558\uc2dc\uba70 \uc9c4\uc9dc \uc2e0\uc559\uc774 \ubb34\uc5c7\uc778\uc9c0 \ub4dc\ub7ec\ub0b4\uc168\uc5b4\uc694. \uac89\uacfc \uc18d\uc774 \ub2e4\ub978 \uc0b6\uc740 \uacb0\uad6d \ud558\ub098\ub2d8 \uc55e\uc5d0\uc11c \uc778\uc815\ubc1b\uc9c0 \ubabb\ud574\uc694. \uc774 \uc7a5\uc740 \ud558\ub098\ub2d8 \uc55e\uc5d0\uc11c \uc9c4\uc2e4\ud55c \uc0b6\uc774 \uc5bc\ub9c8\ub098 \uc911\uc694\ud55c\uc9c0\ub97c \uac15\uc870\ud574\uc694.","\ub098\ub294 \uac89\uacfc \uc18d\uc774 \uac19\uc740 \uc2e0\uc559\uc744 \uac00\uc9c0\uace0 \uc788\ub098\uc694?")
B.Xw=new A.b5("matthew-lesson-25","path-matthew","\uae68\uc5b4 \uc900\ube44\ud558\ub294 \uc0b6","\ub9c8\ud0dc\ubcf5\uc74c 24\uc7a5","\uc608\uc218\ub2d8\uc740 \ub9c8\uc9c0\ub9c9 \ub54c\uc5d0 \uc77c\uc5b4\ub0a0 \uc77c\ub4e4\uacfc \uc7ac\ub9bc\uc5d0 \ub300\ud574 \ub9d0\uc500\ud558\uc168\uc5b4\uc694. \uac70\uc9d3\uacfc \ud63c\ub780\uc774 \ub9ce\uc544\uc9c8 \uac83\uc744 \uacbd\uace0\ud558\uc2dc\uba70 \ubbff\uc74c\uc744 \uc9c0\ud0a4\ub294 \uac83\uc774 \uc911\uc694\ud558\ub2e4\uace0 \ud558\uc168\uc5b4\uc694. \uc5b8\uc81c \uc62c\uc9c0 \uc54c \uc218 \uc5c6\uae30 \ub54c\ubb38\uc5d0 \ud56d\uc0c1 \uc900\ube44\ub41c \uc0c1\ud0dc\ub85c \uc0b4\uc544\uc57c \ud55c\ub2e4\uace0 \uac15\uc870\ud558\uc138\uc694. \uae68\uc5b4 \uc788\ub294 \uc790\uc640 \uadf8\ub807\uc9c0 \uc54a\uc740 \uc790\uc758 \ucc28\uc774\uac00 \ubd84\uba85\ud558\uac8c \ub4dc\ub7ec\ub098\uc694. \uc774 \uc7a5\uc740 \uc9c0\uae08\uc758 \uc0b6\uc774 \uc5bc\ub9c8\ub098 \uc911\uc694\ud55c\uc9c0\ub97c \uae68\ub2eb\uac8c \ud574\uc918\uc694.","\ub098\ub294 \uc900\ube44\ub41c \uc0b6\uc744 \uc0b4\uace0 \uc788\ub098\uc694?")
B.Xl=new A.b5("matthew-lesson-26","path-matthew","\uc900\ube44\uc640 \ucc45\uc784, \uadf8\ub9ac\uace0 \uc0ac\ub791\uc758 \uc2e4\ucc9c","\ub9c8\ud0dc\ubcf5\uc74c 25\uc7a5","\uc5f4 \ucc98\ub140 \ube44\uc720\ub97c \ud1b5\ud574 \uc900\ube44\ub41c \uc790\uc640 \uc900\ube44\ub418\uc9c0 \uc54a\uc740 \uc790\uc758 \ucc28\uc774\ub97c \ubcf4\uc5ec\uc8fc\uc138\uc694. \ub2ec\ub780\ud2b8 \ube44\uc720\ub97c \ud1b5\ud574 \ub9e1\uaca8\uc9c4 \uac83\uc744 \uc5b4\ub5bb\uac8c \uc0ac\uc6a9\ud558\ub294\uc9c0\uac00 \uc911\uc694\ud558\ub2e4\uace0 \uac00\ub974\uce58\uc138\uc694. \uc591\uacfc \uc5fc\uc18c\uc758 \ube44\uc720\uc5d0\uc11c\ub294 \uc791\uc740 \uc790\uc5d0\uac8c \ud55c \uac83\uc774 \uace7 \uc608\uc218\ub2d8\uaed8 \ud55c \uac83\uc774\ub77c\uace0 \ub9d0\uc500\ud558\uc138\uc694. \uc2e0\uc559\uc740 \uae30\ub2e4\ub9bc\ubfd0 \uc544\ub2c8\ub77c \ucc45\uc784\uacfc \ud589\ub3d9\uc774 \ud568\uaed8 \uac00\uc57c \ud574\uc694. \uc774 \uc7a5\uc740 \ubbff\uc74c\uc774 \uc2e4\uc81c \uc0b6\uc73c\ub85c \ub098\ud0c0\ub098\uc57c \ud568\uc744 \uac15\uc870\ud574\uc694.","\ub098\ub294 \uc900\ube44\ub41c \ubbff\uc74c\uc744 \uac00\uc9c0\uace0 \uc788\ub098\uc694?")
B.X8=new A.b5("matthew-lesson-27","path-matthew","\uace0\ub09c \uc18d\uc5d0\uc11c\ub3c4 \uc21c\uc885\ud558\ub294 \uc0b6","\ub9c8\ud0dc\ubcf5\uc74c 26\uc7a5","\uc608\uc218\ub2d8\uc740 \uc2ed\uc790\uac00\ub97c \uc55e\ub450\uace0 \uace0\ub09c\uc744 \uc900\ube44\ud558\uc2dc\uba70 \ud558\ub098\ub2d8\uc758 \ub73b\uc5d0 \uc21c\uc885\ud558\uc138\uc694. \ud55c \uc5ec\uc778\uc740 \ud5a5\uc720\ub97c \ubd80\uc73c\uba70 \uc0ac\ub791\uacfc \ud5cc\uc2e0\uc744 \ub4dc\ub7ec\ub0b4\uc694. \uc81c\uc790\ub4e4\uc740 \uc7a0\ub4e4\uace0, \uc720\ub2e4\ub294 \ubc30\uc2e0\ud558\uba70 \uc778\uac04\uc758 \uc5f0\uc57d\ud568\uc774 \ub4dc\ub7ec\ub098\uc694. \ud558\uc9c0\ub9cc \uc608\uc218\ub2d8\uc740 \ub05d\uae4c\uc9c0 \ud558\ub098\ub2d8\uc758 \uacc4\ud68d\uc744 \ub530\ub974\uc138\uc694. \uc774 \uc7a5\uc740 \uc0c1\ud669\uc774 \uc5b4\ub824\uc6cc\ub3c4 \uc21c\uc885\uc774 \uc911\uc694\ud558\ub2e4\ub294 \uac83\uc744 \ubcf4\uc5ec\uc918\uc694.","\ub098\ub294 \ud558\ub098\ub2d8\uaed8 \uc9c4\uc2ec\uc73c\ub85c \ud5cc\uc2e0\ud558\uace0 \uc788\ub098\uc694?")
B.Wz=new A.b5("matthew-lesson-28","path-matthew","\uc2ed\uc790\uac00\uc758 \uc758\ubbf8\uc640 \uc740\ud61c","\ub9c8\ud0dc\ubcf5\uc74c 27\uc7a5","\uc608\uc218\ub2d8\uc740 \uc8c4\uac00 \uc5c6\uc73c\uc2ec\uc5d0\ub3c4 \ubd88\uad6c\ud558\uace0 \uc2ed\uc790\uac00\uc5d0\uc11c \uc8fd\uc73c\uc168\uc5b4\uc694. \uc0ac\ub78c\ub4e4\uc740 \uc870\ub871\ud558\uace0 \uc678\uba74\ud588\uc9c0\ub9cc \uadf8 \uc8fd\uc74c\uc740 \uc6b0\ub9ac\ub97c \uc704\ud55c \ud76c\uc0dd\uc774\uc5c8\uc5b4\uc694. \uc131\uc804 \ud718\uc7a5\uc774 \ucc22\uc5b4\uc9c0\uba70 \ud558\ub098\ub2d8\uaed8 \ub098\uc544\uac00\ub294 \uae38\uc774 \uc5f4\ub838\uc5b4\uc694. \uc2ed\uc790\uac00\ub294 \uc8c4\uc758 \ubb34\uac8c\uc640 \ud558\ub098\ub2d8\uc758 \uc0ac\ub791\uc744 \ub3d9\uc2dc\uc5d0 \ubcf4\uc5ec\uc918\uc694. \uc774 \uc7a5\uc740 \ubcf5\uc74c\uc758 \ud575\uc2ec\uc744 \uac00\uc7a5 \ubd84\uba85\ud558\uac8c \ub4dc\ub7ec\ub0b4\uc694.","\ub098\ub294 \uc2ed\uc790\uac00\ub97c \uc5b4\ub5bb\uac8c \ubc1b\uc544\ub4e4\uc774\uace0 \uc788\ub098\uc694?")
B.X0=new A.b5("matthew-lesson-29","path-matthew","\ubd80\ud65c\uacfc \uc0ac\uba85","\ub9c8\ud0dc\ubcf5\uc74c 28\uc7a5","\uc608\uc218\ub2d8\uc740 \uc8fd\uc74c\uc744 \uc774\uae30\uace0 \ubd80\ud65c\ud558\uc168\uc5b4\uc694. \uc81c\uc790\ub4e4\uc5d0\uac8c \ub098\ud0c0\ub098\uc154\uc11c \ubaa8\ub4e0 \ubbfc\uc871\uc744 \uc81c\uc790\ub85c \uc0bc\uc73c\ub77c\ub294 \uc0ac\uba85\uc744 \uc8fc\uc168\uc5b4\uc694. \uc138\ub840\ub97c \uc8fc\uace0 \uac00\ub974\uce58\uba70 \ubcf5\uc74c\uc744 \uc804\ud558\ub77c\uace0 \uba85\ub839\ud558\uc138\uc694. \ub610\ud55c \uc138\uc0c1 \ub05d\ub0a0\uae4c\uc9c0 \ud56d\uc0c1 \ud568\uaed8\ud558\uaca0\ub2e4\uace0 \uc57d\uc18d\ud558\uc168\uc5b4\uc694. \uc774 \uc7a5\uc740 \uc2e0\uc559\uc758 \ud575\uc2ec\uc778 \ubd80\ud65c\uacfc \uc6b0\ub9ac\uc758 \uc0ac\uba85\uc744 \ud568\uaed8 \ubcf4\uc5ec\uc918\uc694.","\ub098\ub294 \ubd80\ud65c\uc744 \uc9c4\uc9dc \ubbff\uace0 \uc788\ub098\uc694?")
B.uV=s([B.WU,B.WM,B.WO,B.Xc,B.WB,B.Xo,B.WE,B.WS,B.X6,B.XA,B.Xu,B.Xe,B.Xt,B.Xv,B.X5,B.Wt,B.Xg,B.XC,B.XG,B.WF,B.XD,B.WJ,B.X3,B.Xp,B.Xw,B.Xl,B.X8,B.Wz,B.X0],t.si)
