B.a_u=s([18,15,10,12,15,18,15,12,12],t.n)
B.ar4=new A.pB("\uc6b0\ub9ac \uad50\ud68c",null,null)
B.ar1=new A.pB("\uc804\uccb4 \ub7ad\ud0b9",null,null)
B.a_D=s([B.ar4,B.ar1],t.p)
B.a9U=new A.aX("\uc608\uc218\ub2d8\uc740 \ub204\uad6c\uc2e0\uac00","\ub098\ub294 \ud558\ub098\ub2d8\uc758 \u201c\uc2dc\uac04\ud45c\u201d\ub97c \uc2e0\ub8b0\ud558\uace0 \uc788\ub098\uc694?","\uc544\ube0c\ub77c\ud568\ubd80\ud130 \uc608\uc218\ub2d8\uae4c\uc9c0\ub294 \uc544\uc8fc \uae34 \uc2dc\uac04\uc774 \uac78\ub838\uc9c0\ub9cc,\n\ud558\ub098\ub2d8\uc740 \uadf8 \uc57d\uc18d\uc744 \ub05d\uae4c\uc9c0 \uc774\ub8e8\uc168\uc5b4\uc694.\n\ub098\ub294 \ub0b4 \uc0b6\uc5d0\uc11c\ub3c4\n\uc9c0\uae08 \ub2f9\uc7a5 \ubcf4\uc774\uc9c0 \uc54a\uc544\ub3c4 \ud558\ub098\ub2d8\uc774 \uc77c\ud558\uace0 \uacc4\uc2ec\uc744 \ubbff\uace0 \uc788\ub098\uc694?",1)
B.aav=new A.aX("\uc608\uc218\ub2d8\uc740 \ub204\uad6c\uc2e0\uac00","\ub098\ub294 \ud558\ub098\ub2d8\uc758 \uc774\uc57c\uae30 \uc548\uc5d0 \uc788\ub294 \uc0ac\ub78c\uc774\ub77c\uace0 \uc0dd\uac01\ud558\ub098\uc694?","\uacc4\ubcf4\uc5d0 \ub098\uc624\ub294 \uc0ac\ub78c\ub4e4\uc740 \ud3c9\ubc94\ud55c \uc774\ub984\ucc98\ub7fc \ubcf4\uc774\uc9c0\ub9cc,\n\uacb0\uad6d \ud558\ub098\ub2d8\uc758 \uad6c\uc6d0 \uc5ed\uc0ac\uc5d0 \uc5f0\uacb0\ub41c \uc0ac\ub78c\ub4e4\uc774\uc5d0\uc694.\n\n\ub098\ub294 \ub0b4 \uc0b6\uc774 \ub2e8\uc21c\ud55c \uac1c\uc778\uc758 \uc774\uc57c\uae30\uac00 \uc544\ub2c8\ub77c\n\ud558\ub098\ub2d8\uc758 \ud070 \uacc4\ud68d \uc548\uc5d0 \uc788\ub2e4\uace0 \ubbff\uace0 \uc788\ub098\uc694?",1)
B.aaU=new A.aX("\uc608\uc218\ub2d8\uc740 \ub204\uad6c\uc2e0\uac00","\ub098\ub294 \u201c\uc774\uc5b4\uc9c0\ub294 \ubbff\uc74c\u201d\uc744 \uc0b4\uace0 \uc788\ub098\uc694?","\uacc4\ubcf4\ub294 \ud55c \uc138\ub300\uc5d0\uc11c \ub2e4\uc74c \uc138\ub300\ub85c \uacc4\uc18d \uc774\uc5b4\uc9c0\uba70\n\ud558\ub098\ub2d8\uc758 \uc57d\uc18d\uc774 \uc804\ub2ec\ub418\ub294 \ubaa8\uc2b5\uc744 \ubcf4\uc5ec\uc918\uc694.\n\n\ub098\ub294 \ub0b4 \uc0b6\uc744 \ud1b5\ud574\n\ubbff\uc74c\uc774 \ub2e4\uc74c \uc0ac\ub78c\uc5d0\uac8c \uc774\uc5b4\uc9c0\ub3c4\ub85d \uc0b4\uace0 \uc788\ub098\uc694?",1)
B.aaa=new A.aX("\uc608\uc218\ub2d8\uc758 \ud0c4\uc0dd","\ub098\ub294 \uc774\ud574\ub418\uc9c0 \uc54a\ub294 \uc0c1\ud669\uc5d0\uc11c\ub3c4 \ud558\ub098\ub2d8\uc758 \ub73b\uc744 \uc2e0\ub8b0\ud560 \uc218 \uc788\ub098\uc694?","\uc694\uc149\uc740 \ucc98\uc74c\uc5d0\ub294 \uc774\ud574\ud560 \uc218 \uc5c6\uc5c8\uc9c0\ub9cc\n\ud558\ub098\ub2d8\uc758 \ub9d0\uc500\uc744 \ub4e3\uace0 \uc21c\uc885\ud558\ub294 \uc120\ud0dd\uc744 \ud588\uc5b4\uc694.\n\n\ub098\ub294 \ub0a9\ub4dd\uc774 \ub418\uc9c0 \uc54a\uc544\ub3c4\n\ud558\ub098\ub2d8\uc758 \ub9d0\uc500\uc744 \ub530\ub77c\uac08 \uc218 \uc788\ub098\uc694?",1)
B.aam=new A.aX("\uc608\uc218\ub2d8\uc758 \ud0c4\uc0dd","\ub098\ub294 \u2018\uc758\ub85c\uc6c0\u2019\uc744 \uc5b4\ub5bb\uac8c \uc2e4\ucc9c\ud558\uace0 \uc788\ub098\uc694?","\ub2f9\uc2dc \uc728\ubc95\ub300\ub85c\ub77c\uba74 \ub9c8\ub9ac\uc544\ub97c \ub4dc\ub7ec\ub0b4\uace0 \uad00\uacc4\ub97c \ub04a\ub294 \uac83\ub3c4 \uac00\ub2a5\ud55c \uc120\ud0dd\uc774\uc5c8\uc9c0\ub9cc,\n\uc694\uc149\uc740 \ud558\ub098\ub2d8\uc758 \uacc4\uc2dc\ub97c \ub4e4\uc740 \ud6c4\n\uc790\uc2e0\uc758 \ud310\ub2e8\uacfc \uae30\uc900\uc744 \ub0b4\ub824\ub193\uace0 \ud558\ub098\ub2d8\uc758 \ub73b\uc5d0 \uc790\uc2e0\uc744 \ub9e1\uacbc\uc5b4\uc694.\n\n\ub098\ub294 \ub0b4 \uae30\uc900\uc5d0\uc11c \u201c\uc633\ub2e4\u201d\uace0 \uc0dd\uac01\ud558\ub294 \uac83\uc5d0 \uba38\ubb34\ub974\ub294\uac00\uc694,\n\uc544\ub2c8\uba74 \ud558\ub098\ub2d8\uc758 \ub73b\uc774 \ub4dc\ub7ec\ub0a0 \ub54c \ub0b4 \ud310\ub2e8\uc744 \ub0b4\ub824\ub193\uace0 \uc21c\uc885\ud558\uace0 \uc788\ub098\uc694?",1)
B.ab0=new A.aX("\uc608\uc218\ub2d8\uc758 \ud0c4\uc0dd","\uc608\uc218\ub2d8\uc774 \u2018\ub098\uc758 \uad6c\uc6d0\uc790\u2019\ub77c\ub294 \uc0ac\uc2e4\uc774 \uc2e4\uc81c\ub85c \ub290\uaef4\uc9c0\ub098\uc694?","\uc608\uc218\ub77c\ub294 \uc774\ub984\uc5d0\ub294\n\u201c\uc8c4\uc5d0\uc11c \uad6c\uc6d0\ud558\uc2dc\ub294 \ubd84\u201d\uc774\ub77c\ub294 \uc758\ubbf8\uac00 \ub2f4\uaca8 \uc788\uc5b4\uc694.\n\n\ub098\ub294 \uc608\uc218\ub2d8\uc744 \ub2e8\uc21c\ud55c \uc778\ubb3c\uc774 \uc544\ub2c8\ub77c\n\ub0b4 \uc0b6\uc744 \ubcc0\ud654\uc2dc\ud0a4\ub294 \uad6c\uc6d0\uc790\ub85c \ubc1b\uc544\ub4e4\uc774\uace0 \uc788\ub098\uc694?",1)
B.aay=new A.aX("\ud558\ub098\ub2d8\uc758 \uc778\ub3c4\ud558\uc2ec\uc5d0 \uc21c\uc885\ud558\ub294 \uc0b6","\ub098\ub294 \uc608\uc218\ub2d8\uaed8 \ub098\uc544\uac00\ub294 \uc0ac\ub78c\uc778\uac00\uc694, \ud53c\ud558\ub294 \uc0ac\ub78c\uc778\uac00\uc694?","\ubc15\uc0ac\ub4e4\uc740 \uba3c \uae38\uc744 \uc640\uc11c \uc608\uc218\ub2d8\uaed8 \uacbd\ubc30\ud588\uc9c0\ub9cc,\n\ud5e4\ub86f\uc740 \ub450\ub824\uc6cc\ud558\uba70 \uac70\ubd80\ud588\uc5b4\uc694.\n\n\ub098\ub294 \uc608\uc218\ub2d8\uc744\n\uae30\uc068\uc73c\ub85c \ucc3e\uace0 \uc788\ub098\uc694, \uc544\ub2c8\uba74 \ubd80\ub2f4\uc2a4\ub7ec\uc6cc\ud558\uace0 \uc788\ub098\uc694?",2)
B.aaX=new A.aX("\ud558\ub098\ub2d8\uc758 \uc778\ub3c4\ud558\uc2ec\uc5d0 \uc21c\uc885\ud558\ub294 \uc0b6","\ub098\ub294 \ud558\ub098\ub2d8\uc774 \uc8fc\uc2dc\ub294 \uc778\ub3c4\ud558\uc2ec\uc744 \ub530\ub974\uace0 \uc788\ub098\uc694?","\ubc15\uc0ac\ub4e4\uacfc \uc694\uc149\uc740 \uafc8\uacfc \ub9d0\uc500\uc744 \ud1b5\ud574\n\ud558\ub098\ub2d8\uc758 \uc778\ub3c4\ub97c \ubc1b\uace0 \uadf8\ub300\ub85c \ub530\ub790\uc5b4\uc694.\n\n\ub098\ub294 \ud558\ub098\ub2d8\uc758 \ub73b\uc744 \uc54c \ub54c\n\uc21c\uc885\uc73c\ub85c \ubc18\uc751\ud558\uace0 \uc788\ub098\uc694?",2)
B.aaz=new A.aX("\ud558\ub098\ub2d8\uc758 \uc778\ub3c4\ud558\uc2ec\uc5d0 \uc21c\uc885\ud558\ub294 \uc0b6","\ub098\ub294 \ud558\ub098\ub2d8\uaed8 \ubb34\uc5c7\uc744 \ub4dc\ub9ac\uace0 \uc788\ub098\uc694?","\ubc15\uc0ac\ub4e4\uc740 \uadc0\ud55c \uc608\ubb3c\uc744 \uac00\uc9c0\uace0 \ub098\uc544\uac00\n\uc608\uc218\ub2d8\uaed8 \ub4dc\ub838\uc5b4\uc694.\n\n\ub098\ub294 \uc608\uc218\ub2d8\uaed8\n\uc2dc\uac04, \ub9c8\uc74c, \uc0b6\uc744 \uc9c4\uc2ec\uc73c\ub85c \ub4dc\ub9ac\uace0 \uc788\ub098\uc694?",2)
B.ab4=new A.aX("\ud68c\uac1c\uc640 \uc21c\uc885\uc73c\ub85c \uc900\ube44\ub418\ub294 \uc0b6","\ub098\ub294 \uc9c4\uc9dc \ud68c\uac1c\ud558\uace0 \uc788\ub098\uc694?","\uc138\ub840 \uc694\ud55c\uc740 \ub2e8\uc21c\ud55c \ub9d0\uc774 \uc544\ub2c8\ub77c\n\uc0b6\uc758 \ubcc0\ud654\ub85c \ub098\ud0c0\ub098\ub294 \ud68c\uac1c\ub97c \uac15\uc870\ud588\uc5b4\uc694.\n\n\ub098\ub294 \uc785\uc73c\ub85c\ub9cc\uc774 \uc544\ub2c8\ub77c\n\uc0b6\uc73c\ub85c \ubcc0\ud654\ub418\ub294 \ud68c\uac1c\ub97c \ud558\uace0 \uc788\ub098\uc694?",3)
B.aah=new A.aX("\ud68c\uac1c\uc640 \uc21c\uc885\uc73c\ub85c \uc900\ube44\ub418\ub294 \uc0b6","\ub098\ub294 \ud558\ub098\ub2d8 \uc55e\uc5d0\uc11c \uacb8\uc190\ud55c\uac00\uc694?","\uc138\ub840 \uc694\ud55c\uc740 \ub9ce\uc740 \uc0ac\ub78c\ub4e4\uc5d0\uac8c \uc778\uc815\ubc1b\uc558\uc9c0\ub9cc\n\uc790\uc2e0\uc744 \ub0ae\ucd94\uace0 \uc608\uc218\ub2d8\uc744 \ub192\uc600\uc5b4\uc694.\n\n\ub098\ub294 \uc778\uc815\ubc1b\uc744 \ub54c\n\ub098\ub97c \ub4dc\ub7ec\ub0b4\uace0 \uc788\ub294\uac00, \ud558\ub098\ub2d8\uc744 \ub4dc\ub7ec\ub0b4\uace0 \uc788\ub098\uc694?",3)
B.aa_=new A.aX("\ud68c\uac1c\uc640 \uc21c\uc885\uc73c\ub85c \uc900\ube44\ub418\ub294 \uc0b6","\ub098\ub294 \ud558\ub098\ub2d8\uc758 \ub73b\uc5d0 \uc21c\uc885\ud558\uace0 \uc788\ub098\uc694?","\uc608\uc218\ub2d8\uc870\ucc28 \u201c\ubaa8\ub4e0 \uc758\ub97c \uc774\ub8e8\uae30 \uc704\ud574\u201d\n\uc138\ub840\ub97c \ubc1b\uc73c\uba70 \ud558\ub098\ub2d8\uc758 \ub73b\uc5d0 \uc21c\uc885\ud558\uc168\uc5b4\uc694.\n\n\ub098\ub294 \uc774\ud574\uac00 \ub418\ub4e0 \uc548 \ub418\ub4e0\n\ud558\ub098\ub2d8\uc758 \ub73b \uc55e\uc5d0 \uc21c\uc885\ud558\uace0 \uc788\ub098\uc694?",3)
B.aab=new A.aX("\ub9d0\uc500\uc73c\ub85c \uc2dc\ud5d8\uc744 \uc774\uae30\uace0 \ubd80\ub974\uc2ec\uc5d0 \uc21c\uc885\ud558\ub294 \uc0b6","\ub098\ub294 \uc720\ud639 \uc55e\uc5d0\uc11c \ubb34\uc5c7\uc744 \uae30\uc900\uc73c\ub85c \uc120\ud0dd\ud558\uace0 \uc788\ub098\uc694?","\uc720\ud639\uc740 \ud53c\ud560 \uc218 \uc5c6\uc9c0\ub9cc, \uc5b4\ub5bb\uac8c \ubc18\uc751\ud560\uc9c0\ub294 \uc120\ud0dd\ud560 \uc218 \uc788\uc5b4\uc694. \ub098\ub294 \uac10\uc815\uc774\ub098 \uc0c1\ud669\uc774 \uc544\ub2c8\ub77c \ud558\ub098\ub2d8\uc758 \ub9d0\uc500\uc744 \uae30\uc900\uc73c\ub85c \uc120\ud0dd\ud558\uace0 \uc788\ub098\uc694?",4)
B.aaO=new A.aX("\ub9d0\uc500\uc73c\ub85c \uc2dc\ud5d8\uc744 \uc774\uae30\uace0 \ubd80\ub974\uc2ec\uc5d0 \uc21c\uc885\ud558\ub294 \uc0b6","\ub098\ub294 \ud558\ub098\ub2d8\uc758 \ubd80\ub974\uc2ec\uc5d0 \uc989\uc2dc \ubc18\uc751\ud558\uace0 \uc788\ub098\uc694?","\uc81c\uc790\ub4e4\uc740 \uc900\ube44\ub41c \ud6c4\uc5d0 \ub530\ub978 \uac83\uc774 \uc544\ub2c8\ub77c \ubd80\ub974\uc2ec \uc55e\uc5d0\uc11c \ubc14\ub85c \ubc18\uc751\ud588\uc5b4\uc694. \ub098\ub294 \ud558\ub098\ub2d8\uc758 \ub73b\uc744 \uc54c\uba74\uc11c\ub3c4 \ubbf8\ub8e8\uace0 \uc788\uc9c0\ub294 \uc54a\ub098\uc694?",4)
B.a9V=new A.aX("\ub9d0\uc500\uc73c\ub85c \uc2dc\ud5d8\uc744 \uc774\uae30\uace0 \ubd80\ub974\uc2ec\uc5d0 \uc21c\uc885\ud558\ub294 \uc0b6","\ub098\ub294 \ub9d0\uc500\uc744 \uc544\ub294 \uac83\uc744 \ub118\uc5b4 \uc0b4\uc544\ub0b4\uace0 \uc788\ub098\uc694?","\ub9d0\uc500\uc744 \uc544\ub294 \uac83\uacfc \uc2e4\uc81c\ub85c \uc0ac\ub294 \uac83\uc740 \ub2ec\ub77c\uc694. \ub098\ub294 \ub4e4\uc740 \ub9d0\uc500\uc744 \uc0b6\uc5d0\uc11c \uc2e4\ucc9c\ud558\uace0 \uc788\ub098\uc694?",4)
B.a9X=new A.aX("\ud558\ub098\ub2d8 \ub098\ub77c\uc758 \ubc31\uc131\uc774 \uc0b4\uc544\uac00\ub294 \uc0b6\uc758 \uae30\uc900","\ub098\ub294 \uc138\uc0c1\uc758 \uae30\uc900\uc774 \uc544\ub2cc \ud558\ub098\ub2d8 \uae30\uc900\uc73c\ub85c \uc0b4\uace0 \uc788\ub098\uc694?","\uc138\uc0c1\uc740 \uc131\uacf5, \uc778\uc815, \ud3b8\uc548\ud568\uc744 \uae30\uc900\uc73c\ub85c \ubcf5\uc744 \ub9d0\ud574\uc694. \ud558\uc9c0\ub9cc \ud558\ub098\ub2d8\uc740 \uc804\ud600 \ub2e4\ub978 \uae30\uc900\uc744 \ub9d0\uc500\ud558\uc138\uc694. \ub098\ub294 \uc5b4\ub5a4 \uae30\uc900\uc73c\ub85c \uc0b6\uc744 \ud310\ub2e8\ud558\uace0 \uc788\ub098\uc694?",5)
B.aaM=new A.aX("\ud558\ub098\ub2d8 \ub098\ub77c\uc758 \ubc31\uc131\uc774 \uc0b4\uc544\uac00\ub294 \uc0b6\uc758 \uae30\uc900","\ub098\ub294 \uac89\ubaa8\uc2b5\uc774 \uc544\ub2c8\ub77c \ub9c8\uc74c\uae4c\uc9c0 \ud558\ub098\ub2d8 \uc55e\uc5d0\uc11c \uc815\uc9c1\ud55c\uac00\uc694?","\uc0ac\ub78c\ub4e4\uc740 \ud589\ub3d9\ub9cc \ubcf4\uc9c0\ub9cc \ud558\ub098\ub2d8\uc740 \ub9c8\uc74c\uc744 \ubcf4\uc138\uc694. \ub098\ub294 \uac89\uc73c\ub85c\ub9cc \uad1c\ucc2e\uc740 \ucc99\ud558\uace0 \uc788\uc9c0\ub294 \uc54a\ub098\uc694?",5)
B.aaH=new A.aX("\ud558\ub098\ub2d8 \ub098\ub77c\uc758 \ubc31\uc131\uc774 \uc0b4\uc544\uac00\ub294 \uc0b6\uc758 \uae30\uc900","\ub098\ub294 \uc6d0\uc218\uae4c\uc9c0 \uc0ac\ub791\ud558\ub294 \uc0b6\uc744 \uc0b4\uace0 \uc788\ub098\uc694?","\uc0ac\ub791\ud558\uae30 \uc26c\uc6b4 \uc0ac\ub78c\ub9cc \uc0ac\ub791\ud558\ub294 \uac83\uc740 \ub204\uad6c\ub098 \ud560 \uc218 \uc788\uc5b4\uc694. \ub098\ub294 \ub098\ub97c \ud798\ub4e4\uac8c \ud558\ub294 \uc0ac\ub78c\uc5d0\uac8c\ub3c4 \ud558\ub098\ub2d8\uc758 \ubc29\uc2dd\uc73c\ub85c \uc0ac\ub791\ud558\uace0 \uc788\ub098\uc694?",5)
B.aae=new A.aX("\ud558\ub098\ub2d8 \uc55e\uc5d0\uc11c\uc758 \uc9c4\uc9dc \uacbd\uac74\uacfc \uc0b6\uc758 \uc6b0\uc120\uc21c\uc704","\ub098\ub294 \ud558\ub098\ub2d8\uc774 \uc544\ub2c8\ub77c \uc0ac\ub78c\uc744 \uc758\uc2dd\ud558\uba70 \uc0b4\uace0 \uc788\ub098\uc694?","\uac89\uc73c\ub85c \ub4dc\ub7ec\ub098\ub294 \ud589\ub3d9\ubcf4\ub2e4 \uc911\uc694\ud55c \uac83\uc740 \ub9c8\uc74c\uc758 \ub3d9\uae30\uc608\uc694. \ub098\ub294 \ud558\ub098\ub2d8\uaed8 \ubcf4\uc774\uae30 \uc704\ud574 \uc0b4\uace0 \uc788\ub098\uc694, \uc544\ub2c8\uba74 \uc0ac\ub78c\uc5d0\uac8c \uc778\uc815\ubc1b\uae30 \uc704\ud574 \uc0b4\uace0 \uc788\ub098\uc694?",6)
B.a9W=new A.aX("\ud558\ub098\ub2d8 \uc55e\uc5d0\uc11c\uc758 \uc9c4\uc9dc \uacbd\uac74\uacfc \uc0b6\uc758 \uc6b0\uc120\uc21c\uc704","\ub098\ub294 \ud558\ub098\ub2d8\uc744 \uc2e0\ub8b0\ud558\uba70 \uc5fc\ub824\ub97c \ub0b4\ub824\ub193\uace0 \uc788\ub098\uc694?","\uc5fc\ub824\ub294 \ud558\ub098\ub2d8\uc744 \ubbff\uc9c0 \ubabb\ud560 \ub54c \ucee4\uc838\uc694. \ub098\ub294 \ubb38\uc81c\ubcf4\ub2e4 \ud558\ub098\ub2d8\uc744 \ub354 \ud06c\uac8c \ubcf4\uace0 \uc788\ub098\uc694?",6)
B.aa4=new A.aX("\ud558\ub098\ub2d8 \uc55e\uc5d0\uc11c\uc758 \uc9c4\uc9dc \uacbd\uac74\uacfc \uc0b6\uc758 \uc6b0\uc120\uc21c\uc704","\ub098\ub294 \ud558\ub098\ub2d8 \ub098\ub77c\ub97c \uac00\uc7a5 \uc6b0\uc120\uc73c\ub85c \ub450\uace0 \uc788\ub098\uc694?","\ub9ce\uc740 \uac83\ub4e4\uc774 \uc911\uc694\ud574 \ubcf4\uc774\uc9c0\ub9cc \uc9c4\uc9dc \uc6b0\uc120\uc21c\uc704\ub294 \ud558\ub098\ub2d8\uc774\uc5d0\uc694. \ub098\ub294 \uc9c0\uae08 \ubb34\uc5c7\uc744 \uac00\uc7a5 \uba3c\uc800 \ub450\uace0 \uc0b4\uace0 \uc788\ub098\uc694?",6)
B.aag=new A.aX("\ucc38\ub41c \uc81c\uc790\uc758 \uc0b6\uacfc \uc120\ud0dd","\ub098\ub294 \ub9d0\uc500\uc744 \ub4e3\ub294 \uac83\uc5d0\uc11c \ub05d\ub098\uace0 \uc788\ub098\uc694, \uc544\ub2c8\uba74 \uc2e4\ucc9c\ud558\uace0 \uc788\ub098\uc694?","\uc544\ub294 \uac83\uacfc \uc0ac\ub294 \uac83\uc740 \ub2ec\ub77c\uc694. \ub098\ub294 \ub9d0\uc500\uc744 \uc0b6\uc5d0 \uc801\uc6a9\ud558\uace0 \uc788\ub098\uc694?",7)
B.aaq=new A.aX("\ucc38\ub41c \uc81c\uc790\uc758 \uc0b6\uacfc \uc120\ud0dd","\ub098\ub294 \uc26c\uc6b4 \uae38\uc774 \uc544\ub2c8\ub77c \uc633\uc740 \uae38\uc744 \uc120\ud0dd\ud558\uace0 \uc788\ub098\uc694?","\ub113\uc740 \uae38\uc740 \ud3b8\ud558\uc9c0\ub9cc \uacb0\uad6d \uc0dd\uba85\uc774 \uc544\ub2c8\uc5d0\uc694. \ub098\ub294 \uc5b4\ub5a4 \uae38\uc744 \uc120\ud0dd\ud558\uace0 \uc788\ub098\uc694?",7)
B.aan=new A.aX("\ucc38\ub41c \uc81c\uc790\uc758 \uc0b6\uacfc \uc120\ud0dd","\ub098\ub294 \ub0b4 \uc0b6\uc758 \uae30\ucd08\ub97c \uc5b4\ub514\uc5d0 \ub450\uace0 \uc788\ub098\uc694?","\uc0c1\ud669\uc774 \ud754\ub4e4\ub9b4 \ub54c \ub4dc\ub7ec\ub098\ub294 \uac83\uc774 \uae30\ucd08\uc608\uc694. \ub098\ub294 \ubb34\uc5c7 \uc704\uc5d0 \ub0b4 \uc0b6\uc744 \uc138\uc6b0\uace0 \uc788\ub098\uc694?",7)
B.abd=new A.aX("\uc608\uc218\ub2d8\uc758 \uad8c\uc704\uc640 \ubbff\uc74c","\ub098\ub294 \uc608\uc218\ub2d8\uc758 \uad8c\uc704\ub97c \uc5bc\ub9c8\ub098 \uc2e0\ub8b0\ud558\uace0 \uc788\ub098\uc694?","\ubb38\uc81c\uc758 \ud06c\uae30\ubcf4\ub2e4 \uc608\uc218\ub2d8\uc758 \ub2a5\ub825\uc744 \ub354 \ud06c\uac8c \ubcf4\uace0 \uc788\ub098\uc694?",8)
B.aa1=new A.aX("\uc608\uc218\ub2d8\uc758 \uad8c\uc704\uc640 \ubbff\uc74c","\ub098\ub294 \ub9d0\uc500\ub9cc\uc73c\ub85c\ub3c4 \ubbff\uace0 \uc21c\uc885\ud560 \uc218 \uc788\ub098\uc694?","\ub208\uc5d0 \ubcf4\uc774\uc9c0 \uc54a\uc544\ub3c4 \ubbff\ub294 \uac83\uc774 \uc9c4\uc9dc \ubbff\uc74c\uc774\uc5d0\uc694. \ub098\ub294 \uc870\uac74\uc774 \ud544\uc694\ud558\uc9c0 \uc54a\ub098\uc694?",8)
B.aal=new A.aX("\uc608\uc218\ub2d8\uc758 \uad8c\uc704\uc640 \ubbff\uc74c","\ub098\ub294 \ub450\ub824\uc6c0 \uc18d\uc5d0\uc11c\ub3c4 \ubbff\uc74c\uc744 \uc120\ud0dd\ud558\uace0 \uc788\ub098\uc694?","\uc0c1\ud669\uc774 \ud754\ub4e4\ub9b4 \ub54c \ubbff\uc74c\uc774 \ub4dc\ub7ec\ub098\uc694. \ub098\ub294 \ubb34\uc5c7\uc744 \uc120\ud0dd\ud558\uace0 \uc788\ub098\uc694?",8)
B.aaD=new A.aX("\uc8c4\ub97c \uc0ac\ud558\uc2dc\uace0 \uc0ac\ub78c\uc744 \ubd80\ub974\uc2dc\ub294 \uc608\uc218\ub2d8","\ub098\ub294 \uc608\uc218\ub2d8\uc758 \ubd80\ub974\uc2ec\uc5d0 \uc751\ub2f5\ud558\uace0 \uc788\ub098\uc694?","\ub9c8\ud0dc\ub294 \uc989\uc2dc \ub530\ub790\uc5b4\uc694. \ub098\ub294 \ubbf8\ub8e8\uace0 \uc788\uc9c0 \uc54a\ub098\uc694?",9)
B.aao=new A.aX("\uc8c4\ub97c \uc0ac\ud558\uc2dc\uace0 \uc0ac\ub78c\uc744 \ubd80\ub974\uc2dc\ub294 \uc608\uc218\ub2d8","\ub098\ub294 \ub098\uc758 \uc8c4 \ubb38\uc81c\ub97c \uc608\uc218\ub2d8\uaed8 \ub9e1\uae30\uace0 \uc788\ub098\uc694?","\uac89 \ubb38\uc81c\uac00 \uc544\ub2c8\ub77c \uc8c4\uac00 \ub354 \uadfc\ubcf8\uc774\uc5d0\uc694. \ub098\ub294 \uadf8\uac83\uc744 \uc778\uc815\ud558\uace0 \uc788\ub098\uc694?",9)
B.aaQ=new A.aX("\uc8c4\ub97c \uc0ac\ud558\uc2dc\uace0 \uc0ac\ub78c\uc744 \ubd80\ub974\uc2dc\ub294 \uc608\uc218\ub2d8","\ub098\ub294 \uc0ac\ub78c\uc744 \ubd88\uc30d\ud788 \uc5ec\uae30\ub294 \ub9c8\uc74c\uc774 \uc788\ub098\uc694?","\uc608\uc218\ub2d8\uc740 \uc0ac\ub78c\uc744 \ud310\ub2e8\ud558\uc9c0 \uc54a\uace0 \ubd88\uc30d\ud788 \uc5ec\uae30\uc168\uc5b4\uc694. \ub098\ub294 \uc5b4\ub5a4 \ub9c8\uc74c\uc778\uac00\uc694?",9)
B.a9Y=new A.aX("\uc81c\uc790\uc758 \uc0ac\uba85\uacfc \ub300\uac00","\ub098\ub294 \ubcf5\uc74c\uc744 \uc804\ud558\ub294 \uc0b6\uc744 \uc0b4\uace0 \uc788\ub098\uc694?","\ubbff\uc74c\uc740 \ud63c\uc790\ub9cc\uc758 \uac83\uc774 \uc544\ub2c8\uc5d0\uc694. \ub098\ub294 \ub0b4 \uc8fc\ubcc0 \uc0ac\ub78c\ub4e4\uc5d0\uac8c \ubcf5\uc74c\uc744 \ub098\ub204\uace0 \uc788\ub098\uc694?",10)
B.a9S=new A.aX("\uc81c\uc790\uc758 \uc0ac\uba85\uacfc \ub300\uac00","\ub098\ub294 \uc0ac\ub78c\ubcf4\ub2e4 \ud558\ub098\ub2d8\uc744 \ub354 \ub450\ub824\uc6cc\ud558\uace0 \uc788\ub098\uc694?","\uc0ac\ub78c\uc758 \uc2dc\uc120\uc774 \ub354 \uc911\uc694\ud574\uc9c8 \ub54c\uac00 \ub9ce\uc544\uc694. \ub098\ub294 \ub204\uad6c\ub97c \uae30\uc900\uc73c\ub85c \uc0b4\uace0 \uc788\ub098\uc694?",10)
B.aba=new A.aX("\uc81c\uc790\uc758 \uc0ac\uba85\uacfc \ub300\uac00","\ub098\ub294 \uc608\uc218\ub2d8\uc744 \ub530\ub974\uae30 \uc704\ud574 \ub098\ub97c \ub0b4\ub824\ub193\uc744 \uc218 \uc788\ub098\uc694?","\uc81c\uc790\ub294 \ud3b8\ud55c \uae38\uc774 \uc544\ub2c8\ub77c \ud5cc\uc2e0\uc758 \uae38\uc774\uc5d0\uc694. \ub098\ub294 \ubb34\uc5c7\uc744 \ubd99\uc7a1\uace0 \uc788\ub098\uc694?",10)
B.aai=new A.aX("\uc608\uc218\ub2d8\uc744 \ud5a5\ud55c \ubc18\uc751\uacfc \ucc38\ub41c \uc27c","\ub098\ub294 \uc608\uc218\ub2d8\uc744 \uc758\uc2ec\ud558\uace0 \uc788\ub098\uc694, \uc2e0\ub8b0\ud558\uace0 \uc788\ub098\uc694?","\uc0c1\ud669\uc774 \uc5b4\ub824\uc6b8 \ub54c \ubbff\uc74c\uc774 \ud754\ub4e4\ub9b4 \uc218 \uc788\uc5b4\uc694. \ub098\ub294 \ubb34\uc5c7\uc744 \ubd99\uc7a1\uace0 \uc788\ub098\uc694?",11)
B.aaj=new A.aX("\uc608\uc218\ub2d8\uc744 \ud5a5\ud55c \ubc18\uc751\uacfc \ucc38\ub41c \uc27c","\ub098\ub294 \uc608\uc218\ub2d8\uaed8 \ub098\uc544\uac00 \uc27c\uc744 \uc5bb\uace0 \uc788\ub098\uc694?","\uc0ac\ub78c\uacfc \ud658\uacbd\uc5d0\uc11c \uc27c\uc744 \ucc3e\uace0 \uc788\uc9c0\ub294 \uc54a\ub098\uc694? \uc9c4\uc9dc \uc27c\uc740 \uc5b4\ub514\uc5d0 \uc788\ub098\uc694?",11)
B.aaS=new A.aX("\uc608\uc218\ub2d8\uc744 \ud5a5\ud55c \ubc18\uc751\uacfc \ucc38\ub41c \uc27c","\ub098\ub294 \uacb8\uc190\ud55c \ub9c8\uc74c\uc73c\ub85c \ud558\ub098\ub2d8\uc744 \ubc14\ub77c\ubcf4\uace0 \uc788\ub098\uc694?","\uad50\ub9cc\ud558\uba74 \ud558\ub098\ub2d8\uc744 \ubcfc \uc218 \uc5c6\uc5b4\uc694. \ub098\ub294 \uc5b4\ub5a4 \ub9c8\uc74c \uc0c1\ud0dc\uc778\uac00\uc694?",11)
B.abc=new A.aX("\ucc38\ub41c \uc548\uc2dd\uacfc \ub9c8\uc74c\uc758 \uc0c1\ud0dc","\ub098\ub294 \ud615\uc2dd\uc801\uc778 \uc2e0\uc559\uc5d0 \uba38\ubb3c\ub7ec \uc788\ub098\uc694?","\uac89\uc73c\ub85c\ub294 \uc798\ud558\ub294 \uac83\ucc98\ub7fc \ubcf4\uc5ec\ub3c4 \ub9c8\uc74c\uc740 \ub2e4\ub97c \uc218 \uc788\uc5b4\uc694. \ub098\ub294 \uc5b4\ub5a4\uac00\uc694?",12)
B.aaI=new A.aX("\ucc38\ub41c \uc548\uc2dd\uacfc \ub9c8\uc74c\uc758 \uc0c1\ud0dc","\ub098\ub294 \ud558\ub098\ub2d8\ubcf4\ub2e4 \uaddc\uce59\uc744 \ub354 \uc911\uc694\ud558\uac8c \uc5ec\uae30\uace0 \uc788\ub098\uc694?","\uaddc\uce59\ub3c4 \uc911\uc694\ud558\uc9c0\ub9cc \uc911\uc2ec\uc740 \ud558\ub098\ub2d8\uc774\uc5d0\uc694. \ub098\ub294 \ubb34\uc5c7\uc744 \ub354 \uc911\uc694\ud558\uac8c \uc5ec\uae30\uace0 \uc788\ub098\uc694?",12)
B.ab_=new A.aX("\ucc38\ub41c \uc548\uc2dd\uacfc \ub9c8\uc74c\uc758 \uc0c1\ud0dc","\ub098\ub294 \ub0b4 \ub9c8\uc74c\uc744 \uc798 \uc0b4\ud53c\uace0 \uc788\ub098\uc694?","\ud589\ub3d9\ubcf4\ub2e4 \ub354 \uc911\uc694\ud55c \uac83\uc740 \ub9c8\uc74c\uc774\uc5d0\uc694. \ub098\ub294 \ub0b4 \uc18d\uc744 \ub3cc\uc544\ubcf4\uace0 \uc788\ub098\uc694?",12)
B.aa2=new A.aX("\ud558\ub098\ub2d8 \ub098\ub77c\ub97c \ubc1b\uc544\ub4e4\uc774\ub294 \ub9c8\uc74c","\ub098\ub294 \uc5b4\ub5a4 \ub9c8\uc74c \uc0c1\ud0dc\ub85c \ub9d0\uc500\uc744 \ub4e3\uace0 \uc788\ub098\uc694?","\uac19\uc740 \ub9d0\uc500\ub3c4 \ub9c8\uc74c\uc5d0 \ub530\ub77c \ub2e4\ub974\uac8c \ubc1b\uc544\ub4e4\uc5ec\uc838\uc694. \ub098\ub294 \uc900\ube44\ub41c \ub9c8\uc74c\uc778\uac00\uc694?",13)
B.aaV=new A.aX("\ud558\ub098\ub2d8 \ub098\ub77c\ub97c \ubc1b\uc544\ub4e4\uc774\ub294 \ub9c8\uc74c","\ub098\ub294 \ub9d0\uc500\uc744 \ub4e3\uace0 \uc5f4\ub9e4 \ub9fa\uace0 \uc788\ub098\uc694?","\ub4e3\ub294 \uac83\uc5d0\uc11c \ub05d\ub098\uba74 \uc758\ubbf8 \uc5c6\uc5b4\uc694. \ub0b4 \uc0b6\uc5d0 \ubcc0\ud654\uac00 \uc788\ub098\uc694?",13)
B.aaN=new A.aX("\ud558\ub098\ub2d8 \ub098\ub77c\ub97c \ubc1b\uc544\ub4e4\uc774\ub294 \ub9c8\uc74c","\ub098\ub294 \ud558\ub098\ub2d8 \ub098\ub77c\uc758 \uac00\uce58\ub97c \uc81c\ub300\ub85c \uc54c\uace0 \uc788\ub098\uc694?","\uc138\uc0c1\uc758 \uac00\uce58\uc640 \ud558\ub098\ub2d8\uc758 \uac00\uce58\ub294 \ub2ec\ub77c\uc694. \ub098\ub294 \ubb34\uc5c7\uc744 \ub354 \uc911\uc694\ud558\uac8c \uc5ec\uae30\uace0 \uc788\ub098\uc694?",13)
B.a9R=new A.aX("\ubbff\uc74c\uacfc \uc2dc\uc120","\ub098\ub294 \uc0c1\ud669\uc774 \uc544\ub2c8\ub77c \uc608\uc218\ub2d8\uc744 \ubc14\ub77c\ubcf4\uace0 \uc788\ub098\uc694?","\ubb38\uc81c\ub97c \ubcf4\uba74 \ub450\ub824\uc6c0\uc774 \ucee4\uc9c0\uace0 \uc608\uc218\ub2d8\uc744 \ubcf4\uba74 \ubbff\uc74c\uc774 \ucee4\uc838\uc694. \ub098\ub294 \ubb34\uc5c7\uc744 \ubcf4\uace0 \uc788\ub098\uc694?",14)
B.aaR=new A.aX("\ubbff\uc74c\uacfc \uc2dc\uc120","\ub098\ub294 \ubbff\uc74c\uc73c\ub85c \uc2dc\uc791\ud588\ub2e4\uac00 \ud754\ub4e4\ub9ac\uace0 \uc788\uc9c0\ub294 \uc54a\ub098\uc694?","\ucc98\uc74c\uc5d0\ub294 \ubbff\uc74c\uc73c\ub85c \uc2dc\uc791\ud558\uc9c0\ub9cc \uc911\uac04\uc5d0 \ud754\ub4e4\ub9b4 \uc218 \uc788\uc5b4\uc694. \ub098\ub294 \uc9c0\uae08 \uc5b4\ub514\uc5d0 \uc11c \uc788\ub098\uc694?",14)
B.aa5=new A.aX("\ubbff\uc74c\uacfc \uc2dc\uc120","\ub098\ub294 \uc608\uc218\ub2d8\uaed8 \ub3c4\uc6c0\uc744 \uad6c\ud558\uace0 \uc788\ub098\uc694?","\ubca0\ub4dc\ub85c\ub294 \ube60\uc9c8 \ub54c \uc989\uc2dc \u201c\uc8fc\uc5ec \ub098\ub97c \uad6c\uc6d0\ud558\uc18c\uc11c\u201d\ub77c\uace0 \uc678\ucce4\uc5b4\uc694. \ub098\ub294 \ub3c4\uc6c0\uc744 \uad6c\ud558\uace0 \uc788\ub098\uc694?",14)
B.ab9=new A.aX("\ub9c8\uc74c\uc5d0\uc11c \ub098\uc624\ub294 \uc2e0\uc559","\ub098\ub294 \uac89\uc774 \uc544\ub2c8\ub77c \ub9c8\uc74c\uc774 \ud558\ub098\ub2d8\uaed8 \ud5a5\ud574 \uc788\ub098\uc694?","\uac89\uc73c\ub85c\ub294 \uc2e0\uc559\uc0dd\ud65c\uc744 \uc798\ud574\ub3c4 \ub9c8\uc74c\uc740 \uba40\uc5b4\uc9c8 \uc218 \uc788\uc5b4\uc694. \ub098\ub294 \uc5b4\ub5a4 \uc0c1\ud0dc\uc778\uac00\uc694?",15)
B.aaZ=new A.aX("\ub9c8\uc74c\uc5d0\uc11c \ub098\uc624\ub294 \uc2e0\uc559","\ub098\ub294 \ud3ec\uae30\ud558\uc9c0 \uc54a\ub294 \ubbff\uc74c\uc744 \uac00\uc9c0\uace0 \uc788\ub098\uc694?","\uac00\ub098\uc548 \uc5ec\uc778\uc740 \uac70\uc808\ub2f9\ud574\ub3c4 \ud3ec\uae30\ud558\uc9c0 \uc54a\uc558\uc5b4\uc694. \ub098\ub294 \uc27d\uac8c \ud3ec\uae30\ud558\uace0 \uc788\uc9c0\ub294 \uc54a\ub098\uc694?",15)
B.aaG=new A.aX("\ub9c8\uc74c\uc5d0\uc11c \ub098\uc624\ub294 \uc2e0\uc559","\ub098\ub294 \ud558\ub098\ub2d8\uc744 \uc9c4\uc2ec\uc73c\ub85c \uc2e0\ub8b0\ud558\uace0 \uc788\ub098\uc694?","\uc0c1\ud669\uc774 \uc544\ub2c8\ub77c \ud558\ub098\ub2d8 \uc790\uccb4\ub97c \ubbff\ub294 \uac83\uc774 \uc911\uc694\ud574\uc694. \ub098\ub294 \ubb34\uc5c7\uc744 \ubbff\uace0 \uc788\ub098\uc694?",15)
B.aaB=new A.aX("\uc608\uc218\ub2d8\uc758 \uc815\uccb4\uc131\uacfc \uc81c\uc790\uc758 \uae38","\ub098\ub294 \uc608\uc218\ub2d8\uc744 \ub204\uad6c\ub77c\uace0 \uace0\ubc31\ud558\uace0 \uc788\ub098\uc694?","\ub2e8\uc21c\ud55c \uc9c0\uc2dd\uc774 \uc544\ub2c8\ub77c \uac1c\uc778\uc801\uc778 \uace0\ubc31\uc774 \uc911\uc694\ud574\uc694. \ub098\ub294 \uc5b4\ub5a4 \ubbff\uc74c\uc744 \uac00\uc9c0\uace0 \uc788\ub098\uc694?",16)
B.a9Z=new A.aX("\uc608\uc218\ub2d8\uc758 \uc815\uccb4\uc131\uacfc \uc81c\uc790\uc758 \uae38","\ub098\ub294 \uc2ed\uc790\uac00\ub97c \uc9c0\ub294 \uc0b6\uc744 \uc0b4\uace0 \uc788\ub098\uc694?","\ud3b8\ud55c \uc2e0\uc559\uc774 \uc544\ub2c8\ub77c \ud5cc\uc2e0\uc774 \ud544\uc694\ud574\uc694. \ub098\ub294 \uc5b4\ub5a4 \uc120\ud0dd\uc744 \ud558\uace0 \uc788\ub098\uc694?",16)
B.aaE=new A.aX("\uc608\uc218\ub2d8\uc758 \uc815\uccb4\uc131\uacfc \uc81c\uc790\uc758 \uae38","\ub098\ub294 \ub0b4 \uc0dd\uac01\ubcf4\ub2e4 \ud558\ub098\ub2d8\uc758 \ub73b\uc744 \uc6b0\uc120\ud558\uace0 \uc788\ub098\uc694?","\ubca0\ub4dc\ub85c\ub294 \uc778\uac04\uc801\uc778 \uc0dd\uac01\uc73c\ub85c \uc608\uc218\ub2d8\uc744 \ub9c9\uc558\uc5b4\uc694. \ub098\ub294 \uc5b4\ub5a4 \uae30\uc900\uc73c\ub85c \ud310\ub2e8\ud558\uace0 \uc788\ub098\uc694?",16)
B.aaL=new A.aX("\ud558\ub098\ub2d8\uc758 \uc601\uad11\uacfc \ubbff\uc74c","\ub098\ub294 \ud558\ub098\ub2d8\uc744 \uc5bc\ub9c8\ub098 \ud06c\uac8c \ubcf4\uace0 \uc788\ub098\uc694?","\ud558\ub098\ub2d8\uc744 \uc791\uac8c \ubcf4\uba74 \ubbff\uc74c\ub3c4 \uc791\uc544\uc838\uc694. \ub098\ub294 \ud558\ub098\ub2d8\uc744 \uc5b4\ub5bb\uac8c \ubcf4\uace0 \uc788\ub098\uc694?",17)
B.aad=new A.aX("\ud558\ub098\ub2d8\uc758 \uc601\uad11\uacfc \ubbff\uc74c","\ub098\ub294 \ubbff\uc74c\uc774 \ubd80\uc871\ud55c \uc0c1\ud0dc\uc778\uac00\uc694?","\ubbff\uc74c\uc774 \uc5c6\uc73c\uba74 \uc544\ubb34 \uac83\ub3c4 \ud560 \uc218 \uc5c6\uc5b4\uc694. \ub098\ub294 \uc5b4\ub5a4 \uc0c1\ud0dc\uc778\uac00\uc694?",17)
B.ab6=new A.aX("\ud558\ub098\ub2d8\uc758 \uc601\uad11\uacfc \ubbff\uc74c","\ub098\ub294 \ub9d0\uc500\uc5d0 \uc9d1\uc911\ud558\uace0 \uc788\ub098\uc694?","\ud558\ub098\ub2d8\uc740 \u201c\uadf8\uc758 \ub9d0\uc744 \ub4e4\uc73c\ub77c\u201d\uace0 \ud558\uc168\uc5b4\uc694. \ub098\ub294 \ub4e3\uace0 \uc788\ub098\uc694?",17)
B.ab8=new A.aX("\uacb8\uc190\uacfc \uc6a9\uc11c\uc758 \uacf5\ub3d9\uccb4","\ub098\ub294 \ub0ae\uc544\uc9c0\ub294 \uc0b6\uc744 \uc0b4\uace0 \uc788\ub098\uc694?","\uc138\uc0c1\uc5d0\uc11c\ub294 \ub192\uc544\uc9c0\ub294 \uac83\uc774 \uc911\uc694\ud558\uc9c0\ub9cc \ud558\ub098\ub2d8 \ub098\ub77c\uc5d0\uc11c\ub294 \ub0ae\uc544\uc9c0\ub294 \uac83\uc774 \ub354 \uc911\uc694\ud574\uc694. \ub098\ub294 \uc778\uc815\ubc1b\uace0 \ub192\uc544\uc9c0\ub824\ub294 \ub9c8\uc74c\uc774 \ub354 \ud070\uac00\uc694, \uc544\ub2c8\uba74 \ub0b4\ub824\ub193\uc73c\ub824\ub294 \ub9c8\uc74c\uc774 \uc788\ub098\uc694? \uc624\ub298 \ub0b4\uac00 \ub0ae\uc544\uc9c8 \uc218 \uc788\ub294 \uc120\ud0dd\uc740 \ubb34\uc5c7\uc778\uac00\uc694?",18)
B.a9T=new A.aX("\uacb8\uc190\uacfc \uc6a9\uc11c\uc758 \uacf5\ub3d9\uccb4","\ub098\ub294 \ub2e4\ub978 \uc0ac\ub78c\uc744 \uc9c4\uc2ec\uc73c\ub85c \uc6a9\uc11c\ud558\uace0 \uc788\ub098\uc694?","\uc6a9\uc11c\ub294 \uac10\uc815\uc774 \uc544\ub2c8\ub77c \uc120\ud0dd\uc774\uc5d0\uc694. \ub9c8\uc74c\uc774 \ub530\ub77c\uc624\uc9c0 \uc54a\ub354\ub77c\ub3c4 \uba3c\uc800 \uc6a9\uc11c\ub97c \uc120\ud0dd\ud574\uc57c \ud574\uc694. \ub098\ub294 \uc544\uc9c1 \ub9c8\uc74c\uc18d\uc5d0 \ub0b4\ub824\ub193\uc9c0 \ubabb\ud55c \uc0ac\ub78c\uc774 \uc788\ub098\uc694?",18)
B.aaP=new A.aX("\uacb8\uc190\uacfc \uc6a9\uc11c\uc758 \uacf5\ub3d9\uccb4","\ub098\ub294 \ud55c \uc0ac\ub78c\uc744 \uc18c\uc911\ud558\uac8c \uc5ec\uae30\uace0 \uc788\ub098\uc694?","\ud558\ub098\ub2d8\uc740 \ud55c \uc601\ud63c\ub3c4 \ud3ec\uae30\ud558\uc9c0 \uc54a\uc73c\uc138\uc694. \ub098\ub294 \uc0ac\ub78c\uc744 \uc22b\uc790\ub098 \uc870\uac74\uc73c\ub85c \ud310\ub2e8\ud558\uace0 \uc788\uc9c0\ub294 \uc54a\ub098\uc694? \ub0b4 \uc8fc\ubcc0\uc5d0\uc11c \ub0b4\uac00 \ub354 \uad00\uc2ec \uac00\uc838\uc57c \ud560 \uc0ac\ub78c\uc740 \ub204\uad6c\uc778\uac00\uc694?",18)
B.aau=new A.aX("\ud558\ub098\ub2d8 \ub098\ub77c\uc758 \uac00\uce58\uc640 \uacb0\ub2e8","\ub098\ub294 \ud558\ub098\ub2d8\ubcf4\ub2e4 \ub354 \ubd99\uc7a1\uace0 \uc788\ub294 \uac83\uc774 \uc788\ub098\uc694?","\ud558\ub098\ub2d8\uc744 \ub530\ub974\uae30 \uc704\ud574\uc11c\ub294 \ub0b4\ub824\ub193\uc544\uc57c \ud560 \uac83\uc774 \uc788\uc744 \uc218 \uc788\uc5b4\uc694. \ub098\ub294 \ud3ec\uae30\ud558\uc9c0 \ubabb\ud558\uace0 \ubd99\uc7a1\uace0 \uc788\ub294 \uac83\uc774 \ubb34\uc5c7\uc778\uac00\uc694? \uadf8\uac83\uc774 \ud558\ub098\ub2d8\ubcf4\ub2e4 \ub354 \uc911\uc694\ud55c \uc790\ub9ac\uc5d0 \uc788\uc9c0\ub294 \uc54a\ub098\uc694?",19)
B.abb=new A.aX("\ud558\ub098\ub2d8 \ub098\ub77c\uc758 \uac00\uce58\uc640 \uacb0\ub2e8","\ub098\ub294 \uc5b4\ub9b0\uc544\uc774 \uac19\uc740 \ub9c8\uc74c\uc744 \uac00\uc9c0\uace0 \uc788\ub098\uc694?","\uc5b4\ub9b0\uc544\uc774\ub294 \uc2a4\uc2a4\ub85c \ud574\uacb0\ud558\ub824 \ud558\uc9c0 \uc54a\uace0 \uc758\uc9c0\ud574\uc694. \ub098\ub294 \ub0b4 \ud798\uc73c\ub85c\ub9cc \uc0b4\uc544\uac00\ub824\uace0 \ud558\uace0 \uc788\uc9c0\ub294 \uc54a\ub098\uc694? \ud558\ub098\ub2d8\uc744 \uc5bc\ub9c8\ub098 \uc758\uc9c0\ud558\uace0 \uc788\ub098\uc694?",19)
B.aaY=new A.aX("\ud558\ub098\ub2d8 \ub098\ub77c\uc758 \uac00\uce58\uc640 \uacb0\ub2e8","\ub098\ub294 \uc9c4\uc9dc\ub85c \uc608\uc218\ub2d8\uc744 \ub530\ub974\uace0 \uc788\ub098\uc694?","\ub9d0\ub85c\ub294 \ub530\ub974\ub294 \uac83\ucc98\ub7fc \ubcf4\uc5ec\ub3c4 \uc2e4\uc81c \uc120\ud0dd\uc740 \ub2e4\ub97c \uc218 \uc788\uc5b4\uc694. \ub098\ub294 \uc0b6\uc758 \uc6b0\uc120\uc21c\uc704\ub97c \uc608\uc218\ub2d8\uaed8 \ub450\uace0 \uc788\ub098\uc694? \uc544\ub2c8\uba74 \uc5ec\uc804\ud788 \ub2e4\ub978 \uac83\ub4e4\uc774 \ub354 \uc55e\uc11c\uace0 \uc788\ub098\uc694?",19)
B.aas=new A.aX("\uc740\ud61c\uc640 \uc12c\uae40\uc758 \uc6d0\ub9ac","\ub098\ub294 \ud558\ub098\ub2d8\uc758 \uc740\ud61c\ub97c \ub2f9\uc5f0\ud558\uac8c \uc5ec\uae30\uace0 \uc788\ub098\uc694?","\ub0b4\uac00 \ubc1b\uc740 \uac83\uc740 \ub0b4\uac00 \uc798\ud574\uc11c\uac00 \uc544\ub2c8\ub77c \ud558\ub098\ub2d8\uc774 \uc8fc\uc2e0 \uc740\ud61c\uc608\uc694. \ub098\ub294 \uadf8\uac83\uc744 \uac10\uc0ac\ud558\uba70 \uc0b4\uace0 \uc788\ub098\uc694? \uc544\ub2c8\uba74 \ub2e4\ub978 \uc0ac\ub78c\uacfc \ube44\uad50\ud558\uba70 \ubd88\ud3c9\ud558\uace0 \uc788\ub098\uc694?",20)
B.aaJ=new A.aX("\uc740\ud61c\uc640 \uc12c\uae40\uc758 \uc6d0\ub9ac","\ub098\ub294 \uc12c\uae30\ub294 \uc0b6\uc744 \uc0b4\uace0 \uc788\ub098\uc694?","\uc12c\uae40\uc740 \ub9d0\uc774 \uc544\ub2c8\ub77c \ud589\ub3d9\uc73c\ub85c \ub4dc\ub7ec\ub098\uc694. \ub098\ub294 \ub0ae\uc544\uc9c0\ub294 \uc120\ud0dd\uc744 \ud558\uace0 \uc788\ub098\uc694? \uc544\ub2c8\uba74 \uc778\uc815\ubc1b\uc73c\ub824\ub294 \ub9c8\uc74c\uc774 \ub354 \ud070\uac00\uc694?",20)
B.aaF=new A.aX("\uc740\ud61c\uc640 \uc12c\uae40\uc758 \uc6d0\ub9ac","\ub098\ub294 \ub2e4\ub978 \uc0ac\ub78c\uacfc \ube44\uad50\ud558\uace0 \uc788\ub098\uc694?","\ube44\uad50\ub294 \uac10\uc0ac\ubcf4\ub2e4 \ubd88\ub9cc\uc744 \ub9cc\ub4e4\uc5b4\uc694. \ub098\ub294 \ub204\uad6c\uc640 \ub098\ub97c \ube44\uad50\ud558\uace0 \uc788\ub098\uc694? \ud558\ub098\ub2d8\uc774 \ub098\uc5d0\uac8c \uc8fc\uc2e0 \uac83\uc5d0 \uc9d1\uc911\ud558\uace0 \uc788\ub098\uc694?",20)
B.aa8=new A.aX("\uc655\uc73c\ub85c \uc624\uc2e0 \uc608\uc218\ub2d8\uacfc \uc5f4\ub9e4","\ub098\ub294 \uc5f4\ub9e4 \uc788\ub294 \uc0b6\uc744 \uc0b4\uace0 \uc788\ub098\uc694?","\uc2e0\uc559\uc740 \ub9d0\uc774 \uc544\ub2c8\ub77c \uc0b6\uc758 \uc5f4\ub9e4\ub85c \ub4dc\ub7ec\ub098\uc694. \ub098\ub294 \uac89\uc73c\ub85c\ub9cc \ubbff\ub294 \uac83\ucc98\ub7fc \ubcf4\uc774\uace0 \uc788\uc9c0\ub294 \uc54a\ub098\uc694? \ud558\ub098\ub2d8 \uc55e\uc5d0\uc11c \uc2e4\uc81c\ub85c \ubcc0\ud654\ub41c \ubaa8\uc2b5\uc774 \ub098\ud0c0\ub098\uace0 \uc788\ub098\uc694?",21)
B.aaW=new A.aX("\uc655\uc73c\ub85c \uc624\uc2e0 \uc608\uc218\ub2d8\uacfc \uc5f4\ub9e4","\ub098\ub294 \uc608\uc218\ub2d8\uc758 \uad8c\uc704\ub97c \uc778\uc815\ud558\uace0 \uc788\ub098\uc694?","\uc608\uc218\ub2d8\uc740 \ub0b4 \uc0b6\uc758 \uc8fc\uc778\uc774\uc138\uc694. \ub098\ub294 \uadf8\ubd84\uc758 \ub9d0\uc500\uc744 \uae30\uc900\uc73c\ub85c \uc0b4\uace0 \uc788\ub098\uc694? \uc544\ub2c8\uba74 \ub0b4 \uae30\uc900\uc744 \ub354 \uc55e\uc138\uc6b0\uace0 \uc788\ub098\uc694?",21)
B.aaK=new A.aX("\uc655\uc73c\ub85c \uc624\uc2e0 \uc608\uc218\ub2d8\uacfc \uc5f4\ub9e4","\ub098\ub294 \ub9d0\uacfc \ud589\ub3d9\uc774 \uc77c\uce58\ud558\uace0 \uc788\ub098\uc694?","\ub9d0\ub85c\ub294 \uc21c\uc885\ud55c\ub2e4\uace0 \ud558\uba74\uc11c \uc2e4\uc81c \ud589\ub3d9\uc740 \ub2e4\ub97c \uc218 \uc788\uc5b4\uc694. \ub098\ub294 \ub9d0\ubfd0\uc778 \uc2e0\uc559\uc744 \uac00\uc9c0\uace0 \uc788\uc9c0\ub294 \uc54a\ub098\uc694? \uc624\ub298 \ub0b4\uac00 \ubc14\uafd4\uc57c \ud560 \ud589\ub3d9\uc740 \ubb34\uc5c7\uc778\uac00\uc694?",21)
B.aa9=new A.aX("\ud558\ub098\ub2d8 \ub098\ub77c\uc758 \ucd08\ub300\uc640 \uc0ac\ub791\uc758 \uacc4\uba85","\ub098\ub294 \ud558\ub098\ub2d8 \ub098\ub77c\uc5d0 \uc900\ube44\ub41c \uc0b6\uc744 \uc0b4\uace0 \uc788\ub098\uc694?","\ucd08\ub300\ubc1b\ub294 \uac83\ub9cc\uc73c\ub85c \ucda9\ubd84\ud558\uc9c0 \uc54a\uc544\uc694. \ub098\ub294 \ud558\ub098\ub2d8 \ub098\ub77c\uc5d0 \ud569\ub2f9\ud558\uac8c \uc900\ube44\ub418\uc5b4 \uc788\ub098\uc694? \ub0b4 \uc0b6\uc740 \uadf8 \uae30\uc900\uc5d0 \ub9de\uac8c \ubcc0\ud654\ub418\uace0 \uc788\ub098\uc694?",22)
B.aa6=new A.aX("\ud558\ub098\ub2d8 \ub098\ub77c\uc758 \ucd08\ub300\uc640 \uc0ac\ub791\uc758 \uacc4\uba85","\ub098\ub294 \ud558\ub098\ub2d8\uc744 \uc9c4\uc2ec\uc73c\ub85c \uc0ac\ub791\ud558\uace0 \uc788\ub098\uc694?","\ud558\ub098\ub2d8 \uc0ac\ub791\uc740 \ub9d0\uc774 \uc544\ub2c8\ub77c \uc6b0\uc120\uc21c\uc704\ub85c \ub4dc\ub7ec\ub098\uc694. \ub098\ub294 \ud558\ub098\ub2d8\uc744 \uac00\uc7a5 \uba3c\uc800 \ub450\uace0 \uc788\ub098\uc694? \ub0b4 \uc120\ud0dd\uacfc \uc2dc\uac04\uc740 \ubb34\uc5c7\uc744 \ubcf4\uc5ec\uc8fc\uace0 \uc788\ub098\uc694?",22)
B.aaf=new A.aX("\ud558\ub098\ub2d8 \ub098\ub77c\uc758 \ucd08\ub300\uc640 \uc0ac\ub791\uc758 \uacc4\uba85","\ub098\ub294 \uc774\uc6c3\uc744 \uc0ac\ub791\ud558\uba70 \uc0b4\uace0 \uc788\ub098\uc694?","\ud558\ub098\ub2d8 \uc0ac\ub791\uc740 \ubc18\ub4dc\uc2dc \uc0ac\ub78c \uc0ac\ub791\uc73c\ub85c \uc774\uc5b4\uc838\uc694. \ub098\ub294 \uc8fc\ubcc0 \uc0ac\ub78c\ub4e4\uc744 \uc5b4\ub5bb\uac8c \ub300\ud558\uace0 \uc788\ub098\uc694? \ubd88\ud3b8\ud55c \uc0ac\ub78c\uc5d0\uac8c\ub3c4 \uc0ac\ub791\uc744 \uc2e4\ucc9c\ud558\uace0 \uc788\ub098\uc694?",22)
B.aaA=new A.aX("\uc678\uc2dd\uc774 \uc544\ub2cc \ucc38\ub41c \uc2e0\uc559","\ub098\ub294 \uac89\uacfc \uc18d\uc774 \uac19\uc740 \uc2e0\uc559\uc744 \uac00\uc9c0\uace0 \uc788\ub098\uc694?","\uc0ac\ub78c\uc5d0\uac8c \ubcf4\uc774\ub294 \ubaa8\uc2b5\uacfc \uc2e4\uc81c \ubaa8\uc2b5\uc774 \ub2e4\ub97c \uc218 \uc788\uc5b4\uc694. \ub098\ub294 \ud558\ub098\ub2d8 \uc55e\uc5d0\uc11c\ub3c4 \ub3d9\uc77c\ud55c \ubaa8\uc2b5\uc73c\ub85c \uc11c \uc788\ub098\uc694? \ub0b4 \uc2e0\uc559\uc740 \uc9c4\uc9dc\uc778\uac00\uc694?",23)
