B.aAh=new A.iG("\ub450\ub824\uc6c0\uc744 \uc774\uae30\ub294 \ubbff\uc74c","\ub450\ub824\uc6cc\ud558\uc9c0 \ub9d0\ub77c \ub0b4\uac00 \ub108\uc640 \ud568\uaed8 \ud568\uc774\ub77c\n\ub180\ub77c\uc9c0 \ub9d0\ub77c \ub098\ub294 \ub124 \ud558\ub098\ub2d8\uc774 \ub428\uc774\ub77c\n\ub0b4\uac00 \ub108\ub97c \uad73\uc138\uac8c \ud558\ub9ac\ub77c \ucc38\uc73c\ub85c \ub108\ub97c \ub3c4\uc640\uc8fc\ub9ac\ub77c\n\ucc38\uc73c\ub85c \ub098\uc758 \uc758\ub85c\uc6b4 \uc624\ub978\uc190\uc73c\ub85c \ub108\ub97c \ubd99\ub4e4\ub9ac\ub77c","\uc774\uc0ac\uc57c 41:10",'\uc624\ub298 \ub2f9\uc2e0\uc774 \ub450\ub824\uc6cc\ud558\ub294 \uac83\uc740 \ubb34\uc5c7\uc778\uac00\uc694?\n\ud558\ub098\ub2d8\uc774 "\ub450\ub824\uc6cc\ud558\uc9c0 \ub9d0\ub77c"\uace0 \ub9d0\uc500\ud558\uc2e4 \ub54c, \uadf8 \uc774\uc720\uac00 "\ub0b4\uac00 \ub108\uc640 \ud568\uaed8 \ud568\uc774\ub77c"\uc778 \uac83\uc5d0 \uc8fc\ubaa9\ud574\ubcf4\uc138\uc694.\n\ud568\uaed8\ud558\uc2dc\ub294 \ud558\ub098\ub2d8\uc744 \uc2e0\ub8b0\ud558\uba70, \uc624\ub298\uc758 \ub450\ub824\uc6c0\uc744 \ub0b4\ub824\ub193\uc544 \ubcf4\uc138\uc694.')
B.aAj=new A.iG("\uc27c\uc744 \uc8fc\uc2dc\ub294 \uc608\uc218\ub2d8","\uc218\uace0\ud558\uace0 \ubb34\uac70\uc6b4 \uc9d0 \uc9c4 \uc790\ub4e4\uc544\n\ub2e4 \ub0b4\uac8c\ub85c \uc624\ub77c\n\ub0b4\uac00 \ub108\ud76c\ub97c \uc26c\uac8c \ud558\ub9ac\ub77c","\ub9c8\ud0dc\ubcf5\uc74c 11:28","\uc9c0\uae08 \ub2f9\uc2e0\uc774 \uc9ca\uc5b4\uc9c0\uace0 \uc788\ub294 \ubb34\uac70\uc6b4 \uc9d0\uc740 \ubb34\uc5c7\uc778\uac00\uc694?\n\uc608\uc218\ub2d8\uc740 \uadf8 \uc9d0\uc744 \ub300\uc2e0 \uc838\uc8fc\uaca0\ub2e4\uace0 \ud558\uc2ed\ub2c8\ub2e4.\n\uc624\ub298 \ud558\ub8e8, \uadf8 \uc9d0\uc744 \uc608\uc218\ub2d8\uaed8 \ub0b4\ub824\ub193\ub294 \uc5f0\uc2b5\uc744 \ud574\ubcf4\uc138\uc694.")
B.aAk=new A.iG("\uc5fc\ub824\ub97c \ub9e1\uae30\ub294 \uc0b6","\ub108\ud76c \uc5fc\ub824\ub97c \ub2e4 \uc8fc\uaed8 \ub9e1\uae30\ub77c\n\uc774\ub294 \uadf8\uac00 \ub108\ud76c\ub97c \ub3cc\ubcf4\uc2ec\uc774\ub77c","\ubca0\ub4dc\ub85c\uc804\uc11c 5:7",'\uc624\ub298 \ub9c8\uc74c\uc5d0 \uac78\ub9ac\ub294 \uc5fc\ub824\uac00 \uc788\ub098\uc694?\n\ud558\ub098\ub2d8\uc740 \uc6b0\ub9ac\uc758 \uc791\uc740 \uc5fc\ub824\uae4c\uc9c0\ub3c4 \uad00\uc2ec\uc744 \uac00\uc9c0\uace0 \uacc4\uc2ed\ub2c8\ub2e4.\n"\uadf8\uac00 \ub108\ud76c\ub97c \ub3cc\ubcf4\uc2ec\uc774\ub77c"\ub294 \ub9d0\uc500\uc744 \ub9c8\uc74c\uc5d0 \uc0c8\uaca8\ubcf4\uc138\uc694.')
B.aAg=new A.iG("\ud569\ub825\ud558\uc5ec \uc120\uc744 \uc774\ub8e8\uc2ec","\uc6b0\ub9ac\uac00 \uc54c\uac70\ub2c8\uc640 \ud558\ub098\ub2d8\uc744 \uc0ac\ub791\ud558\ub294 \uc790\n\uace7 \uadf8\uc758 \ub73b\ub300\ub85c \ubd80\ub974\uc2ec\uc744 \uc785\uc740 \uc790\ub4e4\uc5d0\uac8c\ub294\n\ubaa8\ub4e0 \uac83\uc774 \ud569\ub825\ud558\uc5ec \uc120\uc744 \uc774\ub8e8\ub290\ub2c8\ub77c","\ub85c\ub9c8\uc11c 8:28","\uc9c0\uae08\uc740 \uc774\ud574\ub418\uc9c0 \uc54a\ub294 \uc0c1\ud669\uc774 \uc788\ub098\uc694?\n\ud558\ub098\ub2d8\uc740 \ubaa8\ub4e0 \uac83\uc744 \ud569\ub825\ud558\uc5ec \uc120\uc744 \uc774\ub8e8\uc2ed\ub2c8\ub2e4.\n\ud604\uc7ac\uc758 \uc5b4\ub824\uc6c0\ub3c4 \ud558\ub098\ub2d8\uc758 \ud070 \uadf8\ub9bc \uc548\uc5d0 \uc788\uc74c\uc744 \uae30\uc5b5\ud574\ubcf4\uc138\uc694.")
B.aAi=new A.iG("\uc0c8 \ud798\uc744 \uc5bb\ub294 \uc790","\uc624\uc9c1 \uc5ec\ud638\uc640\ub97c \uc559\ub9dd\ud558\ub294 \uc790\ub294 \uc0c8 \ud798\uc744 \uc5bb\uc73c\ub9ac\ub2c8\n\ub3c5\uc218\ub9ac\uac00 \ub0a0\uac1c\uce58\uba70 \uc62c\ub77c\uac10 \uac19\uc744 \uac83\uc774\uc694\n\ub2ec\uc74c\ubc15\uc9c8\ud558\uc5ec\ub3c4 \uace4\ube44\ud558\uc9c0 \uc544\ub2c8\ud558\uaca0\uace0\n\uac78\uc5b4\uac00\ub3c4 \ud53c\uace4\ud558\uc9c0 \uc544\ub2c8\ud558\ub9ac\ub85c\ub2e4","\uc774\uc0ac\uc57c 40:31","\uc9c0\uce58\uace0 \ud798\uc774 \ube60\uc9c4 \ub0a0\uc774 \uc788\ub098\uc694?\n\ud558\ub098\ub2d8\uc744 \uc559\ub9dd(\ubc14\ub77c\ubd04)\ud558\ub294 \uac83\ub9cc\uc73c\ub85c\ub3c4 \uc0c8 \ud798\uc744 \uc5bb\uc744 \uc218 \uc788\uc2b5\ub2c8\ub2e4.\n\uc624\ub298 \uc7a0\uc2dc \uba48\ucd94\uace0, \ud558\ub098\ub2d8\uc744 \ubc14\ub77c\ubcf4\ub294 \uc2dc\uac04\uc744 \uac00\uc838\ubcf4\uc138\uc694.")
B.aAf=new A.iG("\uae38\uc774\uc694 \uc9c4\ub9ac\uc694 \uc0dd\uba85","\uc608\uc218\uaed8\uc11c \uc774\ub974\uc2dc\ub418\n\ub0b4\uac00 \uace7 \uae38\uc774\uc694 \uc9c4\ub9ac\uc694 \uc0dd\uba85\uc774\ub2c8\n\ub098\ub85c \ub9d0\ubbf8\uc554\uc9c0 \uc54a\uace0\ub294\n\uc544\ubc84\uc9c0\uaed8\ub85c \uc62c \uc790\uac00 \uc5c6\ub290\ub2c8\ub77c","\uc694\ud55c\ubcf5\uc74c 14:6",'\uc778\uc0dd\uc5d0\uc11c \uae38\uc744 \uc783\uc740 \uac83 \uac19\uc740 \ub290\ub08c\uc774 \ub4e0 \uc801\uc774 \uc788\ub098\uc694?\n\uc608\uc218\ub2d8\uc740 \uc2a4\uc2a4\ub85c\ub97c "\uae38"\uc774\ub77c\uace0 \ub9d0\uc500\ud558\uc168\uc2b5\ub2c8\ub2e4.\n\uc624\ub298 \uc608\uc218\ub2d8\uc774 \ubcf4\uc5ec\uc8fc\uc2dc\ub294 \uae38\uc744 \ub530\ub77c\uac00\ub294 \uac83\uc5d0 \ub300\ud574 \ubb35\uc0c1\ud574\ubcf4\uc138\uc694.')
B.aAe=new A.iG("\ub0b4\uac8c \ub2a5\ub825 \uc8fc\uc2dc\ub294 \uc790","\ub0b4\uac8c \ub2a5\ub825 \uc8fc\uc2dc\ub294 \uc790 \uc548\uc5d0\uc11c\n\ub0b4\uac00 \ubaa8\ub4e0 \uac83\uc744 \ud560 \uc218 \uc788\ub290\ub2c8\ub77c","\ube4c\ub9bd\ubcf4\uc11c 4:13",'"\ub0b4 \ud798\uc73c\ub85c\ub294 \uc548 \ub3fc"\ub77c\uace0 \ub290\ub07c\ub294 \uc77c\uc774 \uc788\ub098\uc694?\n\ubc14\uc6b8\uc740 \uac10\uc625\uc5d0\uc11c\ub3c4 \uc774 \uace0\ubc31\uc744 \ud588\uc2b5\ub2c8\ub2e4.\n\ub0b4 \ub2a5\ub825\uc774 \uc544\ub2cc, \ub2a5\ub825 \uc8fc\uc2dc\ub294 \ubd84\uc744 \uc758\uc9c0\ud558\ub294 \uac83\uc774 \ud575\uc2ec\uc785\ub2c8\ub2e4.')
B.a1o=s([B.aAh,B.aAj,B.aAk,B.aAg,B.aAi,B.aAf,B.aAe],A.aw("G<iG>"))
B.Xm=new A.b5("mark-lesson-1","path-mark","\ubcf5\uc74c\uc758 \uc2dc\uc791\uacfc \uc989\uac01\uc801\uc778 \uc21c\uc885","\ub9c8\uac00\ubcf5\uc74c 1\uc7a5","\ub9c8\uac00\ubcf5\uc74c\uc740 \uc608\uc218\ub2d8\uc758 \uc0ac\uc5ed\uc744 \ube60\ub974\uac8c \ubcf4\uc5ec\uc8fc\uba70 \ubcf5\uc74c\uc758 \uc2dc\uc791\uc744 \uc120\uc5b8\ud574\uc694. \uc138\ub840 \uc694\ud55c\uc740 \ud68c\uac1c\uc758 \uba54\uc2dc\uc9c0\ub97c \uc804\ud558\uba70 \uc608\uc218\ub2d8\uc758 \uae38\uc744 \uc900\ube44\ud574\uc694. \uc608\uc218\ub2d8\uc740 \uc138\ub840\ub97c \ubc1b\uc73c\uc2dc\uace0 \uace7\ubc14\ub85c \uc2dc\ud5d8\uc744 \uc774\uae30\uc2e0 \ud6c4 \uc0ac\uc5ed\uc744 \uc2dc\uc791\ud558\uc138\uc694. \uc81c\uc790\ub4e4\uc744 \ubd80\ub974\uc2e4 \ub54c \uadf8\ub4e4\uc740 \uc989\uc2dc \ubaa8\ub4e0 \uac83\uc744 \ubc84\ub9ac\uace0 \ub530\ub790\uc5b4\uc694. \uc774 \uc7a5\uc740 \ubcf5\uc74c\uc774 \uc2dc\uc791\ub420 \ub54c \ub098\ud0c0\ub098\ub294 \uc989\uac01\uc801\uc778 \ubc18\uc751\uacfc \uc21c\uc885\uc744 \uac15\uc870\ud574\uc694.","\ub098\ub294 \ud558\ub098\ub2d8\uc758 \ubd80\ub974\uc2ec\uc5d0 \uc989\uc2dc \ubc18\uc751\ud558\uace0 \uc788\ub098\uc694?")
B.WX=new A.b5("mark-lesson-2","path-mark","\uc8c4\ub97c \uc6a9\uc11c\ud558\uc2dc\ub294 \uc608\uc218\ub2d8\uacfc \uc0c8\ub85c\uc6b4 \uae30\uc900","\ub9c8\uac00\ubcf5\uc74c 2\uc7a5","\uc608\uc218\ub2d8\uc740 \uc911\ud48d\ubcd1\uc790\uc758 \uc8c4\ub97c \uba3c\uc800 \uc0ac\ud558\uc2dc\uba70 \uc601\uc801 \uad8c\uc704\ub97c \ub4dc\ub7ec\ub0b4\uc138\uc694. \uc0ac\ub78c\ub4e4\uc740 \ubcd1\uc758 \uce58\uc720\ub97c \uae30\ub300\ud588\uc9c0\ub9cc \uc608\uc218\ub2d8\uc740 \ub354 \uadfc\ubcf8\uc801\uc778 \ubb38\uc81c\ub97c \ub2e4\ub8e8\uc168\uc5b4\uc694. \uc138\ub9ac \ub808\uc704\ub97c \ubd80\ub974\uc2dc\uba70 \uc8c4\uc778\ub3c4 \ubd80\ub974\uc2dc\ub294 \uc740\ud61c\ub97c \ubcf4\uc5ec\uc8fc\uc138\uc694. \uae08\uc2dd\uacfc \uc548\uc2dd\uc77c\uc5d0 \ub300\ud55c \uac00\ub974\uce68\uc744 \ud1b5\ud574 \uc0c8\ub85c\uc6b4 \uc2dc\ub300\ub97c \uc120\ud3ec\ud558\uc138\uc694. \uc774 \uc7a5\uc740 \uc608\uc218\ub2d8\uc774 \uae30\uc874\uc758 \uc885\uad50\uc801 \ud2c0\uc744 \ub118\uc5b4 \uc0c8\ub85c\uc6b4 \uae30\uc900\uc744 \uc138\uc6b0\uc2dc\ub294 \ubaa8\uc2b5\uc744 \ubcf4\uc5ec\uc918\uc694.","\ub098\ub294 \ub0b4 \uc8c4\uc758 \uc0ac\ud568\uc744 \uc608\uc218\ub2d8\uaed8 \ub9e1\uae30\uace0 \uc788\ub098\uc694?")
B.Xy=new A.b5("mark-lesson-3","path-mark","\uc608\uc218\ub2d8\uc758 \uad8c\uc704\uc640 \ucc38\ub41c \uac00\uc871","\ub9c8\uac00\ubcf5\uc74c 3\uc7a5","\uc608\uc218\ub2d8\uc740 \uc548\uc2dd\uc77c\uc5d0 \ubcd1\uc744 \uace0\uce58\uc2dc\uba70 \uc0ac\ub78c\uc744 \uc0b4\ub9ac\ub294 \uac83\uc774 \ub354 \uc911\uc694\ud558\ub2e4\uace0 \uac00\ub974\uce58\uc138\uc694. \ub9ce\uc740 \ubcd1\uc790\ub97c \uace0\uce58\uc2dc\uba70 \uad8c\uc704\ub97c \ub4dc\ub7ec\ub0b4\uc2dc\uace0 \uc5f4\ub450 \uc81c\uc790\ub97c \uc138\uc6b0\uc138\uc694. \uc885\uad50 \uc9c0\ub3c4\uc790\ub4e4\uc740 \uc608\uc218\ub2d8\uc744 \uc624\ud574\ud558\uace0 \ube44\ub09c\ud574\uc694. \uc608\uc218\ub2d8\uc740 \ud558\ub098\ub2d8\uc758 \ub73b\uc744 \ud589\ud558\ub294 \uc0ac\ub78c\uc774 \uc9c4\uc9dc \uac00\uc871\uc774\ub77c\uace0 \ub9d0\uc500\ud558\uc138\uc694. \uc774 \uc7a5\uc740 \uad00\uacc4\uc758 \uae30\uc900\uc774 \ud608\uc5f0\uc774 \uc544\ub2c8\ub77c \ud558\ub098\ub2d8\uacfc\uc758 \uad00\uacc4\uc784\uc744 \ubcf4\uc5ec\uc918\uc694.","\ub098\ub294 \ud558\ub098\ub2d8\uc758 \ub73b\uc744 \uc911\uc2ec\uc73c\ub85c \uc0b4\uace0 \uc788\ub098\uc694?")
B.WA=new A.b5("mark-lesson-4","path-mark","\ub9d0\uc500\uc744 \ubc1b\uc544\ub4e4\uc774\ub294 \ub9c8\uc74c","\ub9c8\uac00\ubcf5\uc74c 4\uc7a5","\uc608\uc218\ub2d8\uc740 \uc528 \ubfcc\ub9ac\ub294 \ube44\uc720\ub97c \ud1b5\ud574 \uc0ac\ub78c\uc758 \ub9c8\uc74c \uc0c1\ud0dc\uc5d0 \ub530\ub77c \ub9d0\uc500\uc774 \ub2e4\ub974\uac8c \ubc1b\uc544\ub4e4\uc5ec\uc9c4\ub2e4\uace0 \uac00\ub974\uce58\uc138\uc694. \uc5b4\ub5a4 \ub9c8\uc74c\uc740 \ub9d0\uc500\uc744 \uae08\ubc29 \uc783\uc5b4\ubc84\ub9ac\uace0, \uc5b4\ub5a4 \ub9c8\uc74c\uc740 \uc5b4\ub824\uc6c0 \ub54c\ubb38\uc5d0 \ud3ec\uae30\ud574\uc694. \uadf8\ub7ec\ub098 \uc900\ube44\ub41c \ub9c8\uc74c\uc740 \ub9d0\uc500\uc744 \ubc1b\uc544\ub4e4\uc774\uace0 \uc5f4\ub9e4\ub97c \ub9fa\uc5b4\uc694. \ub610\ud55c \ub4f1\ubd88\uc758 \ube44\uc720\ub97c \ud1b5\ud574 \ub4dc\ub7ec\ub098\ub294 \ubbff\uc74c\uc758 \uc911\uc694\uc131\uc744 \ub9d0\uc500\ud558\uc138\uc694. \uc774 \uc7a5\uc740 \ub9c8\uc74c\uc758 \uc0c1\ud0dc\uac00 \uc2e0\uc559\uc758 \uacb0\uacfc\ub97c \uacb0\uc815\ud55c\ub2e4\ub294 \uac83\uc744 \ubcf4\uc5ec\uc918\uc694.","\ub098\ub294 \uc5b4\ub5a4 \ub9c8\uc74c\uc73c\ub85c \ub9d0\uc500\uc744 \ub4e3\uace0 \uc788\ub098\uc694?")
B.Xx=new A.b5("mark-lesson-5","path-mark","\ubbff\uc74c\uc73c\ub85c \ub098\uc544\uac00\ub294 \uc0b6","\ub9c8\uac00\ubcf5\uc74c 5\uc7a5","\uc608\uc218\ub2d8\uc740 \uadc0\uc2e0 \ub4e4\ub9b0 \uc0ac\ub78c\uc744 \uc790\uc720\ub86d\uac8c \ud558\uc2dc\uace0, \ubcd1\ub4e0 \uc5ec\uc778\uc744 \uace0\uce58\uc2dc\uba70 \uc8fd\uc740 \uc18c\ub140\ub97c \uc0b4\ub9ac\uc138\uc694. \uac01\uac01\uc758 \uc0c1\ud669\uc5d0\uc11c \ubbff\uc74c\uc774 \uc911\uc694\ud55c \uc5ed\ud560\uc744 \ud574\uc694. \uc0ac\ub78c\ub4e4\uc740 \ub450\ub824\uc6cc\ud588\uc9c0\ub9cc, \uc608\uc218\ub2d8\uc740 \ubbff\uc74c\uc744 \uac15\uc870\ud558\uc138\uc694. \ubbff\uc74c\uc740 \ub2e8\uc21c\ud55c \uc0dd\uac01\uc774 \uc544\ub2c8\ub77c \ud589\ub3d9\uc73c\ub85c \ub098\ud0c0\ub098\uc694. \uc774 \uc7a5\uc740 \uc608\uc218\ub2d8\uaed8 \ub098\uc544\uac00\ub294 \ubbff\uc74c\uc774 \uc0b6\uc744 \ubcc0\ud654\uc2dc\ud0a8\ub2e4\ub294 \uac83\uc744 \ubcf4\uc5ec\uc918\uc694.","\ub098\ub294 \ub450\ub824\uc6c0\ubcf4\ub2e4 \ubbff\uc74c\uc744 \uc120\ud0dd\ud558\uace0 \uc788\ub098\uc694?")
B.WC=new A.b5("mark-lesson-6","path-mark","\ubd88\uc2e0\uacfc \uc21c\uc885\uc758 \ucc28\uc774","\ub9c8\uac00\ubcf5\uc74c 6\uc7a5","\uc608\uc218\ub2d8\uc740 \uace0\ud5a5\uc5d0\uc11c \ubbff\uc9c0 \uc54a\ub294 \uc0ac\ub78c\ub4e4\ub85c \uc778\ud574 \ub9ce\uc740 \uc77c\uc744 \ud558\uc9c0 \uc54a\uc73c\uc138\uc694. \uc81c\uc790\ub4e4\uc744 \ubcf4\ub0b4\uc2e4 \ub54c \uc544\ubb34\uac83\ub3c4 \uc758\uc9c0\ud558\uc9c0 \ub9d0\uace0 \ud558\ub098\ub2d8\ub9cc \uc758\uc9c0\ud558\ub77c\uace0 \ud558\uc138\uc694. \uc624\ubcd1\uc774\uc5b4 \uc0ac\uac74\uc744 \ud1b5\ud574 \ubd80\uc871\ud568 \uc18d\uc5d0\uc11c\ub3c4 \ud558\ub098\ub2d8\uc758 \ub2a5\ub825\uc774 \ub4dc\ub7ec\ub098\uc694. \ud558\uc9c0\ub9cc \uc81c\uc790\ub4e4\uc740 \uc5ec\uc804\ud788 \uc774\ud574\ud558\uc9c0 \ubabb\ud558\uace0 \uc788\uc5b4\uc694. \uc774 \uc7a5\uc740 \ubbff\uc74c\uacfc \ubd88\uc2e0\uc758 \ucc28\uc774\ub97c \ubcf4\uc5ec\uc918\uc694.","\ub098\ub294 \ud558\ub098\ub2d8\uc744 \ubbff\uace0 \uc788\ub098\uc694, \uc544\ub2c8\uba74 \uc758\uc2ec\ud558\uace0 \uc788\ub098\uc694?")
B.X9=new A.b5("mark-lesson-7","path-mark","\ub9c8\uc74c\uc5d0\uc11c \uc2dc\uc791\ub418\ub294 \uc2e0\uc559","\ub9c8\uac00\ubcf5\uc74c 7\uc7a5","\uc608\uc218\ub2d8\uc740 \uc190 \uc53b\ub294 \uaddc\ub840\ub97c \ub450\uace0 \ud615\uc2dd\uc801\uc778 \uc2e0\uc559\uc744 \ucc45\ub9dd\ud558\uc138\uc694. \uc0ac\ub78c\uc744 \ub354\ub7fd\uac8c \ud558\ub294 \uac83\uc740 \uc678\uc801\uc778 \uac83\uc774 \uc544\ub2c8\ub77c \ub9c8\uc74c\uc5d0\uc11c \ub098\uc624\ub294 \uac83\uc774\ub77c\uace0 \ub9d0\uc500\ud558\uc138\uc694. \ub9d0\uacfc \ud589\ub3d9\uc758 \ubfcc\ub9ac\ub294 \ub9c8\uc74c\uc5d0 \uc788\uc5b4\uc694. \ub610\ud55c \uc774\ubc29 \uc5ec\uc778\uc758 \ubbff\uc74c\uc744 \ud1b5\ud574 \uc9c4\uc9dc \ubbff\uc74c\uc774 \ubb34\uc5c7\uc778\uc9c0 \ubcf4\uc5ec\uc8fc\uc138\uc694. \uc774 \uc7a5\uc740 \uc2e0\uc559\uc758 \uc911\uc2ec\uc774 \uac89\uc774 \uc544\ub2c8\ub77c \ub9c8\uc74c\uc774\ub77c\ub294 \uac83\uc744 \uac15\uc870\ud574\uc694.","\ub098\ub294 \uac89\ubcf4\ub2e4 \ub9c8\uc74c\uc744 \ub354 \uc911\uc694\ud558\uac8c \uc5ec\uae30\uace0 \uc788\ub098\uc694?")
B.WK=new A.b5("mark-lesson-8","path-mark","\uc601\uc801\uc778 \ub208\uacfc \ubbff\uc74c","\ub9c8\uac00\ubcf5\uc74c 8\uc7a5",'\uc608\uc218\ub2d8\uc740 \ub610 \ud55c \ubc88 \ub9ce\uc740 \uc0ac\ub78c\uc744 \uba39\uc774\uc2dc\uace0 \uc81c\uc790\ub4e4\uc5d0\uac8c \ubbff\uc74c\uc744 \uac00\ub974\uce58\uc138\uc694. \uadf8\ub7ec\ub098 \uc81c\uc790\ub4e4\uc740 \uc5ec\uc804\ud788 \uae68\ub2eb\uc9c0 \ubabb\ud558\uace0 \uc788\uc5b4\uc694. \uc608\uc218\ub2d8\uc740 "\ub108\ud76c\uac00 \uc544\uc9c1\ub3c4 \uae68\ub2eb\uc9c0 \ubabb\ud558\ub290\ub0d0"\uace0 \ub9d0\uc500\ud558\uc138\uc694. \ubca0\ub4dc\ub85c\ub294 \uc608\uc218\ub2d8\uc744 \uadf8\ub9ac\uc2a4\ub3c4\ub85c \uace0\ubc31\ud558\uc9c0\ub9cc, \uc774\ud6c4 \uc2ed\uc790\uac00\ub97c \uc774\ud574\ud558\uc9c0 \ubabb\ud574\uc694. \uc774 \uc7a5\uc740 \ubbff\uc74c\uc774 \ub2e8\uc21c\ud55c \uc774\ud574\uac00 \uc544\ub2c8\ub77c \uae4a\uc740 \uae68\ub2ec\uc74c\uc774 \ud544\uc694\ud568\uc744 \ubcf4\uc5ec\uc918\uc694.',"\ub098\ub294 \ud558\ub098\ub2d8\uc744 \uc81c\ub300\ub85c \uc774\ud574\ud558\uace0 \uc788\ub098\uc694?")
B.Xk=new A.b5("mark-lesson-9","path-mark","\ubbff\uc74c\uacfc \uacb8\uc190","\ub9c8\uac00\ubcf5\uc74c 9\uc7a5",'\uc608\uc218\ub2d8\uc740 \ubcc0\ud654\uc0b0\uc5d0\uc11c \uc601\uad11\uc744 \ubcf4\uc774\uc2dc\uace0 \uc81c\uc790\ub4e4\uc5d0\uac8c \ud558\ub098\ub2d8\uc758 \uc74c\uc131\uc744 \ub4e3\uac8c \ud558\uc138\uc694. \uc774\ud6c4 \uc81c\uc790\ub4e4\uc774 \uadc0\uc2e0\uc744 \ucad3\uc544\ub0b4\uc9c0 \ubabb\ud558\uc790 \ubbff\uc74c\uc758 \ubd80\uc871\uc744 \uc9c0\uc801\ud558\uc138\uc694. "\ubbff\ub294 \uc790\uc5d0\uac8c\ub294 \ub2a5\uce58 \ubabb\ud560 \uc77c\uc774 \uc5c6\ub2e4"\uace0 \ub9d0\uc500\ud558\uc138\uc694. \ub610\ud55c \ub204\uac00 \ud070 \uc790\uc778\uc9c0 \ub2e4\ud22c\ub294 \uc81c\uc790\ub4e4\uc5d0\uac8c \uc12c\uae40\uacfc \uacb8\uc190\uc744 \uac00\ub974\uce58\uc138\uc694. \uc774 \uc7a5\uc740 \ubbff\uc74c\uacfc \uacb8\uc190\uc774 \ud568\uaed8 \uac00\uc57c \ud568\uc744 \ubcf4\uc5ec\uc918\uc694.',"\ub098\ub294 \ud558\ub098\ub2d8\uc744 \uc5bc\ub9c8\ub098 \ubbff\uace0 \uc788\ub098\uc694?")
B.Wy=new A.b5("mark-lesson-10","path-mark","\ud558\ub098\ub2d8 \ub098\ub77c\uc640 \uc81c\uc790\uc758 \uacb0\ub2e8","\ub9c8\uac00\ubcf5\uc74c 10\uc7a5","\uc608\uc218\ub2d8\uc740 \uacb0\ud63c\uacfc \uc774\ud63c\uc5d0 \ub300\ud574 \ub9d0\uc500\ud558\uc2dc\uba70 \ud558\ub098\ub2d8\uc758 \ub73b\uc744 \uac15\uc870\ud558\uc138\uc694. \uc5b4\ub9b0\uc544\uc774\uc640 \uac19\uc740 \uc790\uac00 \ud558\ub098\ub2d8 \ub098\ub77c\ub97c \ubc1b\ub294\ub2e4\uace0 \ud558\uc2dc\uba70 \uacb8\uc190\uc744 \uac00\ub974\uce58\uc138\uc694. \ubd80\uc790 \uccad\ub144\uc740 \uc608\uc218\ub2d8\uc758 \ubd80\ub974\uc2ec\uc744 \ub4e3\uace0\ub3c4 \uc7ac\ubb3c\uc744 \ub0b4\ub824\ub193\uc9c0 \ubabb\ud574\uc694. \uc608\uc218\ub2d8\uc740 \ud558\ub098\ub2d8 \ub098\ub77c\uc5d0 \ub4e4\uc5b4\uac00\ub294 \uac83\uc774 \uc27d\uc9c0 \uc54a\uc74c\uc744 \ub9d0\uc500\ud558\uc138\uc694. \uc774 \uc7a5\uc740 \ud558\ub098\ub2d8\uc744 \ub530\ub974\uae30 \uc704\ud55c \uacb0\ub2e8\uacfc \uc6b0\uc120\uc21c\uc704\ub97c \ubcf4\uc5ec\uc918\uc694.","\ub098\ub294 \ud558\ub098\ub2d8\ubcf4\ub2e4 \ub354 \ubd99\uc7a1\uace0 \uc788\ub294 \uac83\uc774 \uc788\ub098\uc694?")
B.Xn=new A.b5("mark-lesson-11","path-mark","\ubbff\uc74c\uacfc \uc5f4\ub9e4","\ub9c8\uac00\ubcf5\uc74c 11\uc7a5","\uc608\uc218\ub2d8\uc740 \uc608\ub8e8\uc0b4\ub818\uc5d0 \uc785\uc131\ud558\uc2dc\uace0 \uc131\uc804\uc744 \uc815\uacb0\ud558\uac8c \ud558\uc138\uc694. \ubb34\ud654\uacfc\ub098\ubb34\ub97c \ud1b5\ud574 \uc5f4\ub9e4 \uc5c6\ub294 \uc2e0\uc559\uc744 \ucc45\ub9dd\ud558\uc138\uc694. \ub610\ud55c \ubbff\uc74c\uc73c\ub85c \uae30\ub3c4\ud560 \uac83\uc744 \uac00\ub974\uce58\uc138\uc694. \ud558\ub098\ub2d8\uc744 \ud5a5\ud55c \uc9c4\uc9dc \uc2e0\uc559\uc740 \uc5f4\ub9e4\ub85c \ub4dc\ub7ec\ub098\uc694. \uc774 \uc7a5\uc740 \ubbff\uc74c\uacfc \uc2e4\uc81c \uc0b6\uc758 \uc5f0\uacb0\uc744 \uac15\uc870\ud574\uc694.","\ub098\ub294 \uc5f4\ub9e4 \uc788\ub294 \uc0b6\uc744 \uc0b4\uace0 \uc788\ub098\uc694?")
B.Ww=new A.b5("mark-lesson-12","path-mark","\ud558\ub098\ub2d8 \uc0ac\ub791\uacfc \uc774\uc6c3 \uc0ac\ub791","\ub9c8\uac00\ubcf5\uc74c 12\uc7a5","\uc608\uc218\ub2d8\uc740 \ud3ec\ub3c4\uc6d0 \ube44\uc720\ub97c \ud1b5\ud574 \ud558\ub098\ub2d8\uc758 \ub73b\uc744 \uac70\ubd80\ud558\ub294 \uc0ac\ub78c\ub4e4\uc744 \uacbd\uace0\ud558\uc138\uc694. \ub610\ud55c \uac00\uc7a5 \ud070 \uacc4\uba85\uc73c\ub85c \ud558\ub098\ub2d8 \uc0ac\ub791\uacfc \uc774\uc6c3 \uc0ac\ub791\uc744 \ub9d0\uc500\ud558\uc138\uc694. \uac00\uc774\uc0ac\uc758 \uac83\uacfc \ud558\ub098\ub2d8\uc758 \uac83\uc744 \uad6c\ubd84\ud558\ub77c\uace0 \ud558\uc138\uc694. \ud55c \uacfc\ubd80\uc758 \ud5cc\uae08\uc744 \ud1b5\ud574 \uc9c4\uc9dc \ud5cc\uc2e0\uc774 \ubb34\uc5c7\uc778\uc9c0 \ubcf4\uc5ec\uc8fc\uc138\uc694. \uc774 \uc7a5\uc740 \uc2e0\uc559\uc758 \ubcf8\uc9c8\uc744 \ubd84\uba85\ud558\uac8c \ubcf4\uc5ec\uc918\uc694.","\ub098\ub294 \ud558\ub098\ub2d8\uc744 \uc9c4\uc2ec\uc73c\ub85c \uc0ac\ub791\ud558\uace0 \uc788\ub098\uc694?")
B.WG=new A.b5("mark-lesson-13","path-mark","\uae68\uc5b4 \uc900\ube44\ud558\ub294 \uc0b6","\ub9c8\uac00\ubcf5\uc74c 13\uc7a5","\uc608\uc218\ub2d8\uc740 \ub9c8\uc9c0\ub9c9 \ub54c\uc5d0 \ub300\ud574 \ub9d0\uc500\ud558\uc2dc\uba70 \ud63c\ub780\uacfc \uc5b4\ub824\uc6c0\uc774 \uc788\uc744 \uac83\uc744 \uc54c\ub824\uc8fc\uc138\uc694. \uac70\uc9d3\uacfc \uc720\ud639 \uc18d\uc5d0\uc11c\ub3c4 \ubbff\uc74c\uc744 \uc9c0\ud0a4\ub77c\uace0 \ud558\uc138\uc694. \uc5b8\uc81c \uc62c\uc9c0 \ubaa8\ub974\uae30 \ub54c\ubb38\uc5d0 \ud56d\uc0c1 \uc900\ube44\ub41c \uc0b6\uc744 \uc0b4\uc544\uc57c \ud574\uc694. \uae68\uc5b4 \uc788\ub294 \uac83\uc774 \uc911\uc694\ud558\ub2e4\uace0 \uac15\uc870\ud558\uc138\uc694. \uc774 \uc7a5\uc740 \ud604\uc7ac\uc758 \uc0b6\uc744 \uc5b4\ub5bb\uac8c \uc0b4\uc544\uc57c \ud558\ub294\uc9c0 \ubcf4\uc5ec\uc918\uc694.","\ub098\ub294 \uc900\ube44\ub41c \uc0b6\uc744 \uc0b4\uace0 \uc788\ub098\uc694?")
B.WL=new A.b5("mark-lesson-14","path-mark","\ud5cc\uc2e0\uacfc \uc5f0\uc57d\ud568, \uadf8\ub9ac\uace0 \uc21c\uc885","\ub9c8\uac00\ubcf5\uc74c 14\uc7a5","\ud55c \uc5ec\uc778\uc740 \ud5a5\uc720\ub97c \ubd80\uc73c\uba70 \ud5cc\uc2e0\uc744 \ubcf4\uc5ec\uc918\uc694. \uc81c\uc790\ub4e4\uc740 \ud754\ub4e4\ub9ac\uace0 \uc720\ub2e4\ub294 \ubc30\uc2e0\ud574\uc694. \uc608\uc218\ub2d8\uc740 \uace0\ub09c \uc55e\uc5d0\uc11c\ub3c4 \ud558\ub098\ub2d8\uc758 \ub73b\uc5d0 \uc21c\uc885\ud558\uc138\uc694. \uc778\uac04\uc758 \uc5f0\uc57d\ud568\uacfc \uc608\uc218\ub2d8\uc758 \uc21c\uc885\uc774 \ub300\ube44\ub3fc\uc694. \uc774 \uc7a5\uc740 \uc9c4\uc9dc \ud5cc\uc2e0\uacfc \uc21c\uc885\uc774 \ubb34\uc5c7\uc778\uc9c0 \ubcf4\uc5ec\uc918\uc694.","\ub098\ub294 \ud558\ub098\ub2d8\uaed8 \uc9c4\uc2ec\uc73c\ub85c \ud5cc\uc2e0\ud558\uace0 \uc788\ub098\uc694?")
